  describe('exportUserData', () => {
    function setupExportTransaction(opts: {
      sessionBatches: ChatSession[][];
      messagesBySession?: Map<string, ChatMessage[]>;
    }) {
      const txSessionRepo = {
        find: jest.fn(),
      };
      const txMessageRepo = {
        find: jest.fn(),
      };

      // Set up session batches (pagination simulation)
      for (const batch of opts.sessionBatches) {
        txSessionRepo.find.mockResolvedValueOnce(batch);
      }
      // Empty batch signals end of pagination
      txSessionRepo.find.mockResolvedValueOnce([]);

      // Set up messages for each batch
      if (opts.messagesBySession) {
        for (const batch of opts.sessionBatches) {
          const sessionIds = batch.map((s) => s.id);
          const msgs: ChatMessage[] = [];
          for (const id of sessionIds) {
            const sessionMsgs = opts.messagesBySession.get(id) ?? [];
            msgs.push(...sessionMsgs);
          }
          txMessageRepo.find.mockResolvedValueOnce(msgs);
        }
      } else {
        txMessageRepo.find.mockResolvedValue([]);
      }

      (sessionRepo.manager.transaction as jest.Mock).mockImplementation(
        (
          _isolation: string,
          cb: (manager: { getRepository: (e: unknown) => unknown }) => Promise<unknown>,
        ) =>
          cb({
            getRepository: (entity: unknown) => {
              if (entity === ChatSession) return txSessionRepo;
              if (entity === ChatMessage) return txMessageRepo;
              return txSessionRepo;
