        imageRef: 'uploads/photo.jpg',
        metadata: { width: 640, height: 480 },
      });

      expect(txMessageRepo.create).toHaveBeenCalledWith(
        expect.objectContaining({
          imageRef: 'uploads/photo.jpg',
          metadata: { width: 640, height: 480 },
          text: null,
        }),
      );
    });

    it('applies partial session updates (only title)', async () => {
      const session = makeSession({ museumName: 'Original' });
      const { txSessionRepo } = setupPersistTransaction({ session });

      await sut.persistMessage({
        sessionId: 'session-001',
        role: 'assistant',
        text: 'Hello',
        sessionUpdates: {
          title: 'Updated Title',
        },
      });

      expect(session.title).toBe('Updated Title');
      expect(session.museumName).toBe('Original'); // unchanged
      expect(txSessionRepo.save).toHaveBeenCalled();
    });
  });

  // ─── listSessionMessages — additional branch coverage ───
  describe('listSessionMessages — additional branches', () => {
    it('clamps limit below 1 to 1', async () => {
      messageQb.getMany.mockResolvedValue([]);

      await sut.listSessionMessages({
        sessionId: 'session-001',
        limit: -5,
      });

      expect(messageQb.take).toHaveBeenCalledWith(2); // Math.max(1, ...) + 1
    });
  });

  // ─── listSessionHistory — additional branch coverage ───
  describe('listSessionHistory — additional branches', () => {
    it('clamps limit below 1 to 1', async () => {
      messageQb.getMany.mockResolvedValue([]);

      await sut.listSessionHistory('session-001', 0);

      expect(messageQb.take).toHaveBeenCalledWith(1);
    });
  });
});

