import { UserMemoryService } from '@modules/chat/application/user-memory.service';
import type { UserMemoryRepository } from '@modules/chat/domain/userMemory.repository.interface';
import type { UserMemory } from '@modules/chat/domain/userMemory.entity';
import type { VisitContext } from '@modules/chat/domain/chat.types';
import type { CacheService } from '@shared/cache/cache.port';

// ── Factories ──────────────────────────────────────────────────────────

const makeMemory = (overrides: Partial<UserMemory> = {}): UserMemory =>
  ({
    id: 'mem-uuid',
    userId: 42,
    preferredExpertise: 'beginner',
    favoritePeriods: [],
    favoriteArtists: ['Monet'],
    museumsVisited: ['Louvre'],
    totalArtworksDiscussed: 3,
    notableArtworks: [],
    interests: [],
    summary: null,
    sessionCount: 2,
    lastSessionId: 'sess-prev',
    version: 1,
    createdAt: new Date('2026-01-01'),
    updatedAt: new Date('2026-01-01'),
    ...overrides,
  }) as UserMemory;

const makeRepo = (memory: UserMemory | null = null): jest.Mocked<UserMemoryRepository> => ({
  getByUserId: jest.fn().mockResolvedValue(memory),
  upsert: jest.fn().mockImplementation(async (_userId, updates) => ({
    ...makeMemory(),
    ...updates,
  })),
  deleteByUserId: jest.fn().mockResolvedValue(undefined),
});

const makeCache = (): jest.Mocked<CacheService> => ({
  get: jest.fn().mockResolvedValue(null),
  set: jest.fn().mockResolvedValue(undefined),
  del: jest.fn().mockResolvedValue(undefined),
  delByPrefix: jest.fn().mockResolvedValue(undefined),
  setNx: jest.fn().mockResolvedValue(true),
  ping: jest.fn().mockResolvedValue(true),
});

const makeVisitContext = (overrides: Partial<VisitContext> = {}): VisitContext => ({
  museumName: 'Orsay',
  museumConfidence: 0.9,
  artworksDiscussed: [
    {
      title: 'Water Lilies',
      artist: 'Monet',
      messageId: 'msg-1',
      discussedAt: '2026-01-15T10:00:00Z',
    },
  ],
  roomsVisited: ['Impressionism Hall'],
  detectedExpertise: 'intermediate',
  expertiseSignals: 4,
  lastUpdated: '2026-01-15T10:30:00Z',
  ...overrides,
});

// ── Tests ──────────────────────────────────────────────────────────────

describe('UserMemoryService', () => {
  beforeEach(() => jest.clearAllMocks());

  // ── getMemoryForPrompt ─────────────────────────────────────────────

  describe('getMemoryForPrompt', () => {
    it('returns empty string when user has no memory', async () => {
      const repo = makeRepo(null);
      const svc = new UserMemoryService(repo);

      const result = await svc.getMemoryForPrompt(42);

      expect(result).toBe('');
    });

    it('returns empty string when sessionCount is 0', async () => {
      const repo = makeRepo(makeMemory({ sessionCount: 0 }));
      const svc = new UserMemoryService(repo);

      const result = await svc.getMemoryForPrompt(42);

      expect(result).toBe('');
    });

    it('returns prompt block for existing memory', async () => {
      const repo = makeRepo(makeMemory({ sessionCount: 5, favoriteArtists: ['Monet', 'Renoir'] }));
      const svc = new UserMemoryService(repo);

      const result = await svc.getMemoryForPrompt(42);

      expect(result).toContain('[USER MEMORY]');
      expect(result).toContain('5 sessions');
      expect(result).toContain('Monet');
    });

    it('returns cached value on cache hit', async () => {
      const repo = makeRepo();
      const cache = makeCache();
      cache.get.mockResolvedValue('[USER MEMORY]\nCached block');
      const svc = new UserMemoryService(repo, cache);

      const result = await svc.getMemoryForPrompt(42);

      expect(result).toBe('[USER MEMORY]\nCached block');
      expect(repo.getByUserId).not.toHaveBeenCalled();
    });

    it('stores result in cache after repo fetch', async () => {
      const repo = makeRepo(makeMemory({ sessionCount: 1 }));
      const cache = makeCache();
      const svc = new UserMemoryService(repo, cache);

      await svc.getMemoryForPrompt(42);

      expect(cache.set).toHaveBeenCalledWith('memory:prompt:42', expect.any(String), 3600);
    });
  });

  // ── updateAfterSession ─────────────────────────────────────────────

  describe('updateAfterSession', () => {
    it('increments sessionCount on first session', async () => {
      const repo = makeRepo(null);
      const svc = new UserMemoryService(repo);

      await svc.updateAfterSession(42, null, 'sess-1');

      expect(repo.upsert).toHaveBeenCalledWith(
        42,
        expect.objectContaining({ sessionCount: 1, lastSessionId: 'sess-1' }),
      );
    });

    it('merges museums visited (dedup, capped)', async () => {
      const existing = makeMemory({ museumsVisited: ['Louvre'] });
      const repo = makeRepo(existing);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({ museumName: 'Orsay' });

      await svc.updateAfterSession(42, ctx, 'sess-2');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.museumsVisited).toContain('Louvre');
      expect(upsertCall.museumsVisited).toContain('Orsay');
    });

    it('does not duplicate existing museum (case-insensitive)', async () => {
      const existing = makeMemory({ museumsVisited: ['Orsay'] });
      const repo = makeRepo(existing);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({ museumName: 'orsay' });

      await svc.updateAfterSession(42, ctx, 'sess-2');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.museumsVisited).toBeUndefined(); // no update needed
    });

    it('merges artworks discussed', async () => {
      const existing = makeMemory({ notableArtworks: [], totalArtworksDiscussed: 0 });
      const repo = makeRepo(existing);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext();

      await svc.updateAfterSession(42, ctx, 'sess-2');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.notableArtworks).toHaveLength(1);
      expect(upsertCall.notableArtworks![0].title).toBe('Water Lilies');
      expect(upsertCall.totalArtworksDiscussed).toBe(1);
    });

    it('invalidates cache after update', async () => {
      const repo = makeRepo(null);
      const cache = makeCache();
      const svc = new UserMemoryService(repo, cache);

      await svc.updateAfterSession(42, null, 'sess-1');

      expect(cache.del).toHaveBeenCalledWith('memory:prompt:42');
    });

    it('swallows repository errors (fire-and-forget)', async () => {
      const repo = makeRepo(null);
      repo.upsert.mockRejectedValue(new Error('DB gone'));
      const svc = new UserMemoryService(repo);

      // Should NOT throw
      await expect(svc.updateAfterSession(42, null, 'sess-1')).resolves.toBeUndefined();
    });
  });

  // ── deleteUserMemory ───────────────────────────────────────────────

  describe('deleteUserMemory', () => {
    it('deletes memory and invalidates cache (GDPR)', async () => {
      const repo = makeRepo(makeMemory());
      const cache = makeCache();
      const svc = new UserMemoryService(repo, cache);

      await svc.deleteUserMemory(42);

      expect(repo.deleteByUserId).toHaveBeenCalledWith(42);
      expect(cache.del).toHaveBeenCalledWith('memory:prompt:42');
    });

    it('works without cache configured', async () => {
      const repo = makeRepo();
      const svc = new UserMemoryService(repo);

      await expect(svc.deleteUserMemory(42)).resolves.toBeUndefined();
      expect(repo.deleteByUserId).toHaveBeenCalledWith(42);
    });
  });

  // ── getUserMemory (GDPR export) ─────────────────────────────────────

  describe('getUserMemory', () => {
    it('returns memory entity for existing user', async () => {
      const memory = makeMemory({ userId: 42 });
      const repo = makeRepo(memory);
      const svc = new UserMemoryService(repo);

      const result = await svc.getUserMemory(42);

      expect(result).toEqual(memory);
      expect(repo.getByUserId).toHaveBeenCalledWith(42);
    });

    it('returns null for user with no memory', async () => {
      const repo = makeRepo(null);
      const svc = new UserMemoryService(repo);

      const result = await svc.getUserMemory(42);

      expect(result).toBeNull();
    });
  });

  // ── updateAfterSession (uncovered branches) ─────────────────────────

  describe('updateAfterSession — uncovered branches', () => {
    it('does not merge expertise when expertiseSignals < 3', async () => {
      const repo = makeRepo(null);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({
        detectedExpertise: 'expert',
        expertiseSignals: 2,
      });

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.preferredExpertise).toBeUndefined();
    });

    it('merges expertise when detectedExpertise is set and signals >= 3', async () => {
      const repo = makeRepo(null);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({
        detectedExpertise: 'expert',
        expertiseSignals: 5,
      });

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.preferredExpertise).toBe('expert');
    });

    it('does not merge museum when museumName is undefined', async () => {
      const repo = makeRepo(null);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({ museumName: undefined });

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.museumsVisited).toBeUndefined();
    });

    it('does not merge artists when no artworks have artist names', async () => {
      const repo = makeRepo(null);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({
        artworksDiscussed: [
          {
            title: 'Unknown Painting',
            artist: undefined,
            messageId: 'msg-1',
            discussedAt: '2026-01-01T00:00:00Z',
          },
        ],
      });

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.favoriteArtists).toBeUndefined();
    });

    it('deduplicates artists (case-insensitive)', async () => {
      const existing = makeMemory({ favoriteArtists: ['Monet'] });
      const repo = makeRepo(existing);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({
        artworksDiscussed: [
          {
            title: 'Painting',
            artist: 'monet',
            messageId: 'msg-1',
            discussedAt: '2026-01-01T00:00:00Z',
          },
        ],
      });

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.favoriteArtists).toBeUndefined(); // duplicate, no update
    });

    it('adds new artists that are not duplicates', async () => {
      const existing = makeMemory({ favoriteArtists: ['Monet'] });
      const repo = makeRepo(existing);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({
        artworksDiscussed: [
          {
            title: 'Painting',
            artist: 'Renoir',
            messageId: 'msg-1',
            discussedAt: '2026-01-01T00:00:00Z',
          },
        ],
      });

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.favoriteArtists).toEqual(['Monet', 'Renoir']);
    });

    it('does not merge artworks when artworksDiscussed is empty', async () => {
      const repo = makeRepo(null);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({ artworksDiscussed: [] });

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.notableArtworks).toBeUndefined();
      expect(upsertCall.totalArtworksDiscussed).toBeUndefined();
    });

    it('sets museum on notable artwork from visit context', async () => {
      const existing = makeMemory({ notableArtworks: [], totalArtworksDiscussed: 0 });
      const repo = makeRepo(existing);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({ museumName: 'Orsay' });

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.notableArtworks![0].museum).toBe('Orsay');
    });

    it('sets museum to undefined when museumName is null-like', async () => {
      const existing = makeMemory({ notableArtworks: [], totalArtworksDiscussed: 0 });
      const repo = makeRepo(existing);
      const svc = new UserMemoryService(repo);
      const ctx = makeVisitContext({ museumName: undefined });
      // Override artworksDiscussed to have at least one entry
      ctx.artworksDiscussed = [
        {
          title: 'Art',
          artist: 'Artist',
          messageId: 'msg-1',
          discussedAt: '2026-01-01T00:00:00Z',
        },
      ];

      await svc.updateAfterSession(42, ctx, 'sess-1');

      const upsertCall = repo.upsert.mock.calls[0][1];
      expect(upsertCall.notableArtworks![0].museum).toBeUndefined();
    });
  });

  // ── invalidateCache ─────────────────────────────────────────────────

  describe('invalidateCache', () => {
    it('does nothing when no cache is configured', async () => {
      const repo = makeRepo();
      const svc = new UserMemoryService(repo);

      await expect(svc.invalidateCache(42)).resolves.toBeUndefined();
    });

    it('deletes cache key when cache is configured', async () => {
      const repo = makeRepo();
      const cache = makeCache();
      const svc = new UserMemoryService(repo, cache);

      await svc.invalidateCache(42);

      expect(cache.del).toHaveBeenCalledWith('memory:prompt:42');
    });
  });

  // ── getMemoryForPrompt (uncovered branch: cache miss, no cache) ─────

  describe('getMemoryForPrompt — uncovered branches', () => {
    it('fetches from repo and does not store when no cache configured', async () => {
      const repo = makeRepo(makeMemory({ sessionCount: 1 }));
      const svc = new UserMemoryService(repo);

      const result = await svc.getMemoryForPrompt(42);

      expect(repo.getByUserId).toHaveBeenCalledWith(42);
      expect(result).toContain('[USER MEMORY]');
    });

    it('fetches from repo when cache returns null', async () => {
      const repo = makeRepo(makeMemory({ sessionCount: 1 }));
      const cache = makeCache();
      cache.get.mockResolvedValue(null);
      const svc = new UserMemoryService(repo, cache);

      const result = await svc.getMemoryForPrompt(42);

      expect(repo.getByUserId).toHaveBeenCalledWith(42);
      expect(cache.set).toHaveBeenCalled();
      expect(result).toContain('[USER MEMORY]');
    });
  });
});

tests/unit/chat/chat-message-route.test..source:
import request from 'supertest';

import { AppError } from '@shared/errors/app.error';
import { env } from '@src/config/env';
import { createApp } from '@src/app';
import {
  resetRateLimits,
  stopRateLimitSweep,
} from 'tests/helpers/http/route-test-setup';
import { userToken, makeToken } from 'tests/helpers/auth/token.helpers';

import type { ChatService } from '@modules/chat/application/chat.service';

// ── Mock ChatService ────────────────────────────────────────────────

const mockPostMessage = jest.fn();
const mockPostMessageStream = jest.fn();
const mockCreateSession = jest.fn();
const mockListSessions = jest.fn();
const mockGetSession = jest.fn();
const mockDeleteSessionIfEmpty = jest.fn();
const mockReportMessage = jest.fn();
const mockGetMessageImageRef = jest.fn();
const mockSetMessageFeedback = jest.fn();
const mockPostAudioMessage = jest.fn();
const mockSynthesizeSpeech = jest.fn();

const mockChatService: Partial<ChatService> = {
  createSession: mockCreateSession,
  listSessions: mockListSessions,
  getSession: mockGetSession,
  deleteSessionIfEmpty: mockDeleteSessionIfEmpty,
  postMessage: mockPostMessage,
  postMessageStream: mockPostMessageStream,
  reportMessage: mockReportMessage,
  getMessageImageRef: mockGetMessageImageRef,
  setMessageFeedback: mockSetMessageFeedback,
  postAudioMessage: mockPostAudioMessage,
  synthesizeSpeech: mockSynthesizeSpeech,
};

const app = createApp({
  chatService: mockChatService as ChatService,
  healthCheck: async () => ({ database: 'up' }),
});

// ── Helpers ────────────────────────────────────────────────────────

/** Parse SSE event stream into structured events. */
function parseSseEvents(raw: string): Array<{ event: string; data: unknown }> {
  const events: Array<{ event: string; data: unknown }> = [];
  const blocks = raw.split('\n\n').filter(Boolean);
  for (const block of blocks) {
    const lines = block.split('\n');
    let event = '';
    let data = '';
    for (const line of lines) {
      if (line.startsWith('event: ')) event = line.slice(7);
      if (line.startsWith('data: ')) data = line.slice(6);
    }
    if (event && data) {
      try {
        events.push({ event, data: JSON.parse(data) });
      } catch {
        events.push({ event, data });
      }
    }
  }
  return events;
}

// ── Tests ──────────────────────────────────────────────────────────

describe('chat-message.route — uncovered paths', () => {
  const originalStreaming = env.featureFlags.streaming;

  beforeEach(() => {
    resetRateLimits();
    jest.clearAllMocks();
    env.featureFlags.streaming = originalStreaming;
  });

  afterAll(() => {
    env.featureFlags.streaming = originalStreaming;
    stopRateLimitSweep();
  });

  // ── Streaming feature flag disabled ────────────────────────────

  describe('POST /api/chat/sessions/:id/messages/stream — feature flag OFF', () => {
    it('returns 404 when streaming feature flag is disabled', async () => {
      env.featureFlags.streaming = false;

      const res = await request(app)
        .post('/api/chat/sessions/session-uuid/messages/stream')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'hello' });

      expect(res.status).toBe(404);
      expect(res.body.error.code).toBe('NOT_FOUND');
      expect(res.body.error.message).toBe('Streaming not enabled');
    });
  });

  // ── Streaming SSE happy path + callbacks ───────────────────────

  describe('POST /api/chat/sessions/:id/messages/stream — SSE streaming', () => {
    beforeEach(() => {
      env.featureFlags.streaming = true;
    });

    it('streams tokens via SSE and sends done event', async () => {
      mockPostMessageStream.mockImplementation(
        async (_sessionId: string, _input: unknown, callbacks: {
          onToken: (text: string) => void;
        }) => {
          callbacks.onToken('Hello');
          callbacks.onToken(' world');
          return {
            message: {
              id: 'msg-stream-1',
              createdAt: '2026-01-01T00:00:00.000Z',
            },
            metadata: { detectedArtwork: { title: 'Test Art' } },
          };
        },
      );

      const res = await request(app)
        .post('/api/chat/sessions/session-uuid/messages/stream')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'Tell me about art' });

      expect(res.status).toBe(200);
      expect(res.headers['content-type']).toContain('text/event-stream');

      const events = parseSseEvents(res.text);
      const tokenEvents = events.filter((e) => e.event === 'token');
      const doneEvents = events.filter((e) => e.event === 'done');

      expect(tokenEvents).toHaveLength(2);
      expect(tokenEvents[0].data).toEqual({ t: 'Hello' });
      expect(tokenEvents[1].data).toEqual({ t: ' world' });
      expect(doneEvents).toHaveLength(1);
      expect(doneEvents[0].data).toEqual(
        expect.objectContaining({ messageId: 'msg-stream-1' }),
      );
    });

    it('sends guardrail event via onGuardrail callback', async () => {
      mockPostMessageStream.mockImplementation(
        async (_sessionId: string, _input: unknown, callbacks: {
          onToken: (text: string) => void;
          onGuardrail?: (text: string, reason: string) => void;
        }) => {
          callbacks.onGuardrail?.('This topic is not art-related', 'OFF_TOPIC');
          return {
            message: {
              id: 'msg-guardrail-1',
              createdAt: '2026-01-01T00:00:00.000Z',
            },
            metadata: {},
          };
        },
      );

      const res = await request(app)
        .post('/api/chat/sessions/session-uuid/messages/stream')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'How do I cook pasta?' });

      expect(res.status).toBe(200);

      const events = parseSseEvents(res.text);
      const guardrailEvents = events.filter((e) => e.event === 'guardrail');

      expect(guardrailEvents).toHaveLength(1);
      expect(guardrailEvents[0].data).toEqual({
        text: 'This topic is not art-related',
        reason: 'OFF_TOPIC',
      });
    });

    it('sends error SSE event when AppError is thrown', async () => {
      mockPostMessageStream.mockRejectedValue(
        new AppError({
          message: 'Session not found',
          statusCode: 404,
          code: 'NOT_FOUND',
        }),
      );

      const res = await request(app)
        .post('/api/chat/sessions/bad-session/messages/stream')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'hello' });

      expect(res.status).toBe(200);

      const events = parseSseEvents(res.text);
      const errorEvents = events.filter((e) => e.event === 'error');

      expect(errorEvents).toHaveLength(1);
      expect(errorEvents[0].data).toEqual({
        code: 'NOT_FOUND',
        message: 'Session not found',
      });
    });

    it('sends generic error SSE event for non-AppError exceptions', async () => {
      mockPostMessageStream.mockRejectedValue(new Error('DB connection lost'));

      const res = await request(app)
        .post('/api/chat/sessions/bad-session/messages/stream')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'hello' });

      expect(res.status).toBe(200);

      const events = parseSseEvents(res.text);
      const errorEvents = events.filter((e) => e.event === 'error');

      expect(errorEvents).toHaveLength(1);
      expect(errorEvents[0].data).toEqual({
        code: 'INTERNAL_ERROR',
        message: 'Internal server error',
      });
    });

    it('passes currentUserId and requestId to postMessageStream', async () => {
      mockPostMessageStream.mockResolvedValue({
        message: { id: 'msg-1', createdAt: '2026-01-01T00:00:00.000Z' },
        metadata: {},
      });

      await request(app)
        .post('/api/chat/sessions/session-uuid/messages/stream')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'hello' });

      expect(mockPostMessageStream).toHaveBeenCalledWith(
        'session-uuid',
        expect.objectContaining({ text: 'hello' }),
        expect.objectContaining({
          onToken: expect.any(Function),
          onGuardrail: expect.any(Function),
          requestId: expect.any(String),
          currentUserId: 1,
          signal: expect.any(AbortSignal),
        }),
      );
    });

    it('parses JSON context string in stream request body', async () => {
      mockPostMessageStream.mockResolvedValue({
        message: { id: 'msg-1', createdAt: '2026-01-01T00:00:00.000Z' },
        metadata: {},
      });

      await request(app)
        .post('/api/chat/sessions/session-uuid/messages/stream')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({
          text: 'hello',
          context: JSON.stringify({ locale: 'fr', location: 'Louvre' }),
        });

      expect(mockPostMessageStream).toHaveBeenCalledWith(
        'session-uuid',
        expect.objectContaining({
          text: 'hello',
          context: expect.objectContaining({ locale: 'fr', location: 'Louvre' }),
        }),
        expect.any(Object),
      );
    });
  });

  // ── Non-streaming POST /sessions/:id/messages ──────────────────

  describe('POST /api/chat/sessions/:id/messages — non-streaming path', () => {
    it('returns 201 with assistant reply on success', async () => {
      const result = {
        sessionId: 'session-uuid',
        message: {
          id: 'msg-uuid',
          role: 'assistant',
          text: 'The Mona Lisa is a masterpiece.',
          createdAt: '2026-01-01T00:00:00.000Z',
        },
        metadata: { detectedArtwork: { title: 'Mona Lisa' } },
      };
      mockPostMessage.mockResolvedValueOnce(result);

      const res = await request(app)
        .post('/api/chat/sessions/session-uuid/messages')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'Tell me about the Mona Lisa' });

      expect(res.status).toBe(201);
      expect(res.body).toEqual(result);
    });

    it('forwards AppError from chatService as structured error', async () => {
      mockPostMessage.mockRejectedValueOnce(
        new AppError({
          message: 'Session not found',
          statusCode: 404,
          code: 'NOT_FOUND',
        }),
      );

      const res = await request(app)
        .post('/api/chat/sessions/missing-session/messages')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'hello' });

      expect(res.status).toBe(404);
      expect(res.body.error.code).toBe('NOT_FOUND');
    });

    it('forwards non-AppError as 500', async () => {
      mockPostMessage.mockRejectedValueOnce(new Error('DB exploded'));

      const res = await request(app)
        .post('/api/chat/sessions/session-uuid/messages')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'hello' });

      expect(res.status).toBe(500);
    });

    it('parses context from JSON string in multipart-like body', async () => {
      mockPostMessage.mockResolvedValueOnce({
        sessionId: 'session-uuid',
        message: { id: 'msg-1', role: 'assistant', text: 'reply', createdAt: '2026-01-01T00:00:00.000Z' },
        metadata: {},
      });

      await request(app)
        .post('/api/chat/sessions/session-uuid/messages')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({
          text: 'hello',
          context: JSON.stringify({ locale: 'de', museumMode: true }),
        });

      expect(mockPostMessage).toHaveBeenCalledWith(
        'session-uuid',
        expect.objectContaining({
          text: 'hello',
          context: expect.objectContaining({ locale: 'de', museumMode: true }),
        }),
        expect.any(String),
        1,
      );
    });

    it('handles image from body as base64', async () => {
      mockPostMessage.mockResolvedValueOnce({
        sessionId: 'session-uuid',
        message: { id: 'msg-1', role: 'assistant', text: 'reply', createdAt: '2026-01-01T00:00:00.000Z' },
        metadata: {},
      });

      await request(app)
        .post('/api/chat/sessions/session-uuid/messages')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'What is this?', image: 'iVBORw0KGgo...' });

      expect(mockPostMessage).toHaveBeenCalledWith(
        'session-uuid',
        expect.objectContaining({
          image: expect.objectContaining({
            source: 'base64',
            value: 'iVBORw0KGgo...',
          }),
        }),
        expect.any(String),
        1,
      );
    });

    it('handles image URL from body', async () => {
      mockPostMessage.mockResolvedValueOnce({
        sessionId: 'session-uuid',
        message: { id: 'msg-1', role: 'assistant', text: 'reply', createdAt: '2026-01-01T00:00:00.000Z' },
        metadata: {},
      });

      await request(app)
        .post('/api/chat/sessions/session-uuid/messages')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ text: 'What is this?', image: 'https://example.com/painting.jpg' });

      expect(mockPostMessage).toHaveBeenCalledWith(
        'session-uuid',
        expect.objectContaining({
          image: expect.objectContaining({
            source: 'url',
            value: 'https://example.com/painting.jpg',
          }),
        }),
        expect.any(String),
        1,
      );
    });

    it('handles request with no user on req (e.g. anonymous)', async () => {
      const tokenNoSub = makeToken({ sub: undefined });
      mockPostMessage.mockResolvedValueOnce({
        sessionId: 's-1',
        message: { id: 'm-1', role: 'assistant', text: 'ok', createdAt: '2026-01-01T00:00:00.000Z' },
        metadata: {},
      });

      // The auth middleware may reject this; the important thing is we don't crash
      const res = await request(app)
        .post('/api/chat/sessions/session-uuid/messages')
        .set('Authorization', `Bearer ${tokenNoSub}`)
        .send({ text: 'hello' });

      // Either 201 (if auth passes with undefined id) or 401
      expect([201, 401]).toContain(res.status);
    });
  });

  // ── Art keywords endpoints ─────────────────────────────────────

  describe('GET /api/chat/art-keywords — no artKeywordRepo', () => {
    it('returns 404 when artKeywordRepo is not provided', async () => {
      // The app is created without artKeywordRepo, so this should return 404
      const res = await request(app)
        .get('/api/chat/art-keywords')
        .set('Authorization', `Bearer ${userToken()}`);

      expect(res.status).toBe(404);
      expect(res.body.error.code).toBe('NOT_FOUND');
    });
  });

  describe('POST /api/chat/art-keywords — no artKeywordRepo', () => {
    it('returns 404 when artKeywordRepo is not provided', async () => {
      const res = await request(app)
        .post('/api/chat/art-keywords')
        .set('Authorization', `Bearer ${userToken()}`)
        .send({ keywords: ['monet'] });

      expect(res.status).toBe(404);
      expect(res.body.error.code).toBe('NOT_FOUND');
    });
  });
});

