import { SearchMuseumsUseCase } from '@modules/museum/core/useCase/searchMuseums.useCase';
import { InMemoryMuseumRepository } from 'tests/helpers/museum/inMemoryMuseumRepository';
import type { OverpassMuseumResult } from '@shared/http/overpass.client';
import type { NominatimGeocodingResult } from '@shared/http/nominatim.client';
import type { CacheService } from '@shared/cache/cache.port';

/* ------------------------------------------------------------------ */
/*  Mock: Overpass client                                              */
/* ------------------------------------------------------------------ */
const mockQueryOverpassMuseums = jest.fn<Promise<OverpassMuseumResult[]>, []>();

jest.mock('@shared/http/overpass.client', () => ({
  queryOverpassMuseums: (...args: unknown[]) => mockQueryOverpassMuseums(...(args as [])),
}));

/* ------------------------------------------------------------------ */
/*  Mock: Nominatim client                                             */
/* ------------------------------------------------------------------ */
const mockGeocodeWithNominatim = jest.fn<Promise<NominatimGeocodingResult | null>, []>();

jest.mock('@shared/http/nominatim.client', () => ({
  geocodeWithNominatim: (...args: unknown[]) => mockGeocodeWithNominatim(...(args as [])),
}));

/* ------------------------------------------------------------------ */
/*  Mock: env (needed for cache TTL)                                   */
/* ------------------------------------------------------------------ */
jest.mock('@src/config/env', () => ({
  env: { overpassCacheTtlSeconds: 3600 },
}));

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

/** Paris coordinates (reference point for all tests). */
const PARIS = { lat: 48.8566, lng: 2.3522 };

/**
 * Creates an OSM result near a given offset from Paris.
 * @param name
 * @param latOffset
 * @param lonOffset
 * @param osmId
 */
const makeOsmResult = (
  name: string,
  latOffset: number,
  lonOffset: number,
  osmId = 100,
): OverpassMuseumResult => ({
  name,
  address: null,
  latitude: PARIS.lat + latOffset,
  longitude: PARIS.lng + lonOffset,
  osmId,
});

/** Creates a minimal in-memory cache for testing. */
function createMockCache(): CacheService {
  const store = new Map<string, unknown>();
  return {
    get: jest.fn(async (key: string) => {
      return store.get(key) ?? null;
    }) as CacheService['get'],
    set: jest.fn(async (key: string, value: unknown, _ttl?: number) => {
      store.set(key, value);
    }) as CacheService['set'],
    del: jest.fn(async () => {}),
    delByPrefix: jest.fn(async () => {}),
    setNx: jest.fn(async () => true) as CacheService['setNx'],
    ping: jest.fn(async () => true),
  };
}

/* ------------------------------------------------------------------ */
/*  Tests                                                              */
/* ------------------------------------------------------------------ */

describe('SearchMuseumsUseCase', () => {
  let repo: InMemoryMuseumRepository;
  let useCase: SearchMuseumsUseCase;

  beforeEach(() => {
    repo = new InMemoryMuseumRepository();
    useCase = new SearchMuseumsUseCase(repo);
    mockQueryOverpassMuseums.mockReset();
    mockQueryOverpassMuseums.mockResolvedValue([]);
    mockGeocodeWithNominatim.mockReset();
    mockGeocodeWithNominatim.mockResolvedValue(null);
  });

  it('returns merged results from Overpass + local DB', async () => {
    await repo.create({
      name: 'Louvre',
      slug: 'louvre',
      latitude: 48.8606,
      longitude: 2.3376,
    });

    mockQueryOverpassMuseums.mockResolvedValueOnce([
      makeOsmResult('Palais de Tokyo', 0.005, -0.05, 200),
    ]);

    const result = await useCase.execute({ ...PARIS, radiusMeters: 10_000 });

    expect(result.museums).toHaveLength(2);
    expect(result.count).toBe(2);

    const names = result.museums.map((m) => m.name);
    expect(names).toContain('Louvre');
    expect(names).toContain('Palais de Tokyo');
  });

  it('deduplicates by proximity — prefers local when within 100m', async () => {
    // Local museum at exact coords
    await repo.create({
      name: 'Louvre (local)',
      slug: 'louvre-local',
      latitude: 48.8606,
      longitude: 2.3376,
    });

    // OSM result within ~10m of the local museum
    mockQueryOverpassMuseums.mockResolvedValueOnce([
      {
        name: 'Louvre (osm)',
        address: null,
        latitude: 48.8607,
        longitude: 2.3377,
        osmId: 999,
      },
    ]);

    const result = await useCase.execute({ ...PARIS, radiusMeters: 10_000 });

    // Only the local version should survive
    expect(result.museums).toHaveLength(1);
    expect(result.museums[0].name).toBe('Louvre (local)');
    expect(result.museums[0].source).toBe('local');
  });

  it('calculates distance correctly (haversine)', async () => {
    // Place museum ~1km north of PARIS center
    // ~0.009 degrees latitude is approximately 1km
    await repo.create({
      name: 'Nearby Museum',
      slug: 'nearby',
      latitude: PARIS.lat + 0.009,
      longitude: PARIS.lng,
    });

    const result = await useCase.execute({ ...PARIS, radiusMeters: 5000 });

    expect(result.museums).toHaveLength(1);
    // Distance should be ~1000m (haversine allows some tolerance)
    expect(result.museums[0].distance).toBeGreaterThan(900);
    expect(result.museums[0].distance).toBeLessThan(1100);
  });

  it('sorts results by distance ascending', async () => {
    // Far museum
    await repo.create({
      name: 'Far Museum',
      slug: 'far',
      latitude: PARIS.lat + 0.04,
      longitude: PARIS.lng,
    });

    // Close museum
    await repo.create({
      name: 'Close Museum',
      slug: 'close',
      latitude: PARIS.lat + 0.001,
      longitude: PARIS.lng,
    });

    // Medium museum
    await repo.create({
      name: 'Medium Museum',
      slug: 'medium',
      latitude: PARIS.lat + 0.02,
      longitude: PARIS.lng,
    });

    const result = await useCase.execute({ ...PARIS, radiusMeters: 50_000 });

    expect(result.museums.map((m) => m.name)).toEqual([
      'Close Museum',
      'Medium Museum',
      'Far Museum',
    ]);
  });

  it('respects max radius (caps at 50km)', async () => {
    // Museum at ~60km away (~0.54 degrees latitude)
    await repo.create({
      name: 'Very Far Museum',
      slug: 'very-far',
      latitude: PARIS.lat + 0.54,
      longitude: PARIS.lng,
    });

    // Museum within 50km
    await repo.create({
      name: 'Within Range',
      slug: 'within-range',
      latitude: PARIS.lat + 0.1,
      longitude: PARIS.lng,
    });

    // Request radius of 100km — should be capped to 50km
    const result = await useCase.execute({ ...PARIS, radiusMeters: 100_000 });

    expect(result.museums).toHaveLength(1);
    expect(result.museums[0].name).toBe('Within Range');
  });

  it('falls back to local-only when Overpass fails', async () => {
    await repo.create({
      name: 'Louvre',
      slug: 'louvre',
      latitude: 48.8606,
      longitude: 2.3376,
    });

    // Overpass returns empty on failure (the client catches errors internally)
    mockQueryOverpassMuseums.mockResolvedValueOnce([]);

    const result = await useCase.execute({ ...PARIS, radiusMeters: 10_000 });

    expect(result.museums).toHaveLength(1);
    expect(result.museums[0].name).toBe('Louvre');
    expect(result.museums[0].source).toBe('local');
  });

  it('uses cache on second call', async () => {
    const cache = createMockCache();
    const cachedUseCase = new SearchMuseumsUseCase(repo, cache);

    const osmResults = [makeOsmResult('Cached Museum', 0.001, 0.001, 300)];
    mockQueryOverpassMuseums.mockResolvedValueOnce(osmResults);

    // First call — should fetch from Overpass and cache
    await cachedUseCase.execute({ ...PARIS, radiusMeters: 10_000 });
    expect(mockQueryOverpassMuseums).toHaveBeenCalledTimes(1);
    expect(cache.set).toHaveBeenCalledTimes(1);

    // Second call — should use cache, not call Overpass again
    await cachedUseCase.execute({ ...PARIS, radiusMeters: 10_000 });
    expect(mockQueryOverpassMuseums).toHaveBeenCalledTimes(1); // still 1
    expect(cache.get).toHaveBeenCalledTimes(2);
  });

  it('filters results by q parameter', async () => {
    await repo.create({
      name: 'Louvre Museum',
      slug: 'louvre',
      latitude: 48.8606,
      longitude: 2.3376,
    });

    await repo.create({
      name: "Musee d'Orsay",
      slug: 'orsay',
      latitude: 48.8599,
      longitude: 2.3266,
    });

    mockQueryOverpassMuseums.mockResolvedValueOnce([
      makeOsmResult('Palais de Tokyo', 0.005, -0.05, 200),
    ]);

    const result = await useCase.execute({ ...PARIS, radiusMeters: 10_000, q: 'louvre' });

    expect(result.museums).toHaveLength(1);
    expect(result.museums[0].name).toBe('Louvre Museum');
  });

  it('returns source "local" for DB museums and "osm" for Overpass results', async () => {
    await repo.create({
      name: 'Local Museum',
      slug: 'local',
      latitude: PARIS.lat + 0.001,
      longitude: PARIS.lng,
    });

    mockQueryOverpassMuseums.mockResolvedValueOnce([makeOsmResult('OSM Museum', 0.01, 0.01, 500)]);

    const result = await useCase.execute({ ...PARIS, radiusMeters: 10_000 });

    const local = result.museums.find((m) => m.name === 'Local Museum');
    const osm = result.museums.find((m) => m.name === 'OSM Museum');

    expect(local?.source).toBe('local');
    expect(osm?.source).toBe('osm');
  });

  it('uses default radius of 30km when not provided', async () => {
    // Museum at ~8km (within default 30km radius)
    await repo.create({
      name: 'Within Default',
      slug: 'within-default',
      latitude: PARIS.lat + 0.07,
      longitude: PARIS.lng,
    });

    // Museum at ~25km (within default 30km radius)
    await repo.create({
      name: 'Also Within Default',
      slug: 'also-within-default',
      latitude: PARIS.lat + 0.22,
      longitude: PARIS.lng,
    });

    // Museum at ~40km (outside default 30km radius)
    await repo.create({
      name: 'Outside Default',
      slug: 'outside-default',
      latitude: PARIS.lat + 0.36,
      longitude: PARIS.lng,
    });

    const result = await useCase.execute({ lat: PARIS.lat, lng: PARIS.lng });

    expect(result.museums).toHaveLength(2);
    const names = result.museums.map((m) => m.name);
    expect(names).toContain('Within Default');
    expect(names).toContain('Also Within Default');
    expect(names).not.toContain('Outside Default');
  });

  it('excludes local museums without coordinates', async () => {
    await repo.create({
      name: 'No Coords Museum',
      slug: 'no-coords',
      // no latitude/longitude
    });

    await repo.create({
      name: 'Has Coords Museum',
      slug: 'has-coords',
      latitude: PARIS.lat + 0.001,
      longitude: PARIS.lng,
    });

    const result = await useCase.execute({ ...PARIS, radiusMeters: 10_000 });

    expect(result.museums).toHaveLength(1);
    expect(result.museums[0].name).toBe('Has Coords Museum');
  });

  it('geocodes text-only search via Nominatim then searches Overpass', async () => {
    // Nominatim resolves "Lyon" to Lyon coordinates
    const LYON = { lat: 45.764, lng: 4.8357 };
    mockGeocodeWithNominatim.mockResolvedValueOnce(LYON);

    mockQueryOverpassMuseums.mockResolvedValueOnce([
      {
        name: 'Musee des Beaux-Arts de Lyon',
        address: null,
        latitude: 45.767,
        longitude: 4.833,
        osmId: 400,
      },
    ]);

    const result = await useCase.execute({ q: 'Lyon' });

    expect(mockGeocodeWithNominatim).toHaveBeenCalledWith('Lyon');
    expect(mockQueryOverpassMuseums).toHaveBeenCalledTimes(1);
    expect(result.museums).toHaveLength(1);
    expect(result.museums[0].name).toBe('Musee des Beaux-Arts de Lyon');
    expect(result.museums[0].source).toBe('osm');
  });

  it('returns local DB museums only when no params provided', async () => {
    await repo.create({
      name: 'Generic Museum',
      slug: 'generic',
      latitude: 48.86,
      longitude: 2.34,
    });

    const result = await useCase.execute({});

    // No coordinates → no Overpass call, no Nominatim call
    expect(mockQueryOverpassMuseums).not.toHaveBeenCalled();
    expect(mockGeocodeWithNominatim).not.toHaveBeenCalled();

    expect(result.museums).toHaveLength(1);
    expect(result.museums[0].name).toBe('Generic Museum');
    expect(result.museums[0].source).toBe('local');
    expect(result.museums[0].distance).toBe(0);
  });

  it('falls back to local DB when Nominatim geocoding fails', async () => {
    mockGeocodeWithNominatim.mockResolvedValueOnce(null);

    await repo.create({
      name: 'Musee de Lyon',
      slug: 'lyon-museum',
      latitude: 45.764,
      longitude: 4.836,
    });

    await repo.create({
      name: 'Musee de Paris',
      slug: 'paris-museum',
      latitude: 48.86,
      longitude: 2.34,
    });

    const result = await useCase.execute({ q: 'Lyon' });

    // Nominatim failed → no coordinates → no Overpass
    expect(mockQueryOverpassMuseums).not.toHaveBeenCalled();

    // Should filter local museums by q
    expect(result.museums).toHaveLength(1);
    expect(result.museums[0].name).toBe('Musee de Lyon');
  });

  it('skips Nominatim when lat/lng are already provided', async () => {
    mockQueryOverpassMuseums.mockResolvedValueOnce([]);

    const result = await useCase.execute({ ...PARIS, q: 'test' });

    expect(mockGeocodeWithNominatim).not.toHaveBeenCalled();
    expect(mockQueryOverpassMuseums).toHaveBeenCalledTimes(1);
    expect(result.museums).toHaveLength(0);
  });
});

tests/unit/chat/image-storage.s3.test.ts.source:
import http from 'http';

import {
  S3CompatibleImageStorage,
  buildS3ImageRef,
  buildS3PresignedReadUrl,
  buildS3SignedReadUrlFromRef,
  isS3ImageRef,
  parseS3ImageRef,
  listObjectsByPrefix,
  deleteObjectsBatch,
} from '@modules/chat/adapters/secondary/image-storage.s3';

const config = {
  endpoint: 'https://storage.example.com',
  region: 'auto',
  bucket: 'museum-private',
  accessKeyId: 'test-access-key',
  secretAccessKey: 'test-secret-key',
  signedUrlTtlSeconds: 900,
};

describe('image-storage.s3', () => {
  it('parses and detects s3 image refs', () => {
    const imageRef = buildS3ImageRef('chat-images/2026/02/test.png');

    expect(isS3ImageRef(imageRef)).toBe(true);
    expect(parseS3ImageRef(imageRef)).toEqual({
      key: 'chat-images/2026/02/test.png',
    });
    expect(isS3ImageRef('local://abc.png')).toBe(false);
    expect(parseS3ImageRef('local://abc.png')).toBeNull();
  });

  it('builds deterministic presigned read urls', () => {
    const now = new Date('2026-02-23T10:00:00.000Z');
    const result = buildS3PresignedReadUrl({
      key: 'chat-images/2026/02/test image.png',
      config,
      ttlSeconds: 300,
      now,
    });

    const url = new URL(result.url);
    expect(url.origin).toBe('https://storage.example.com');
    expect(url.pathname).toBe('/museum-private/chat-images/2026/02/test%20image.png');
    expect(url.searchParams.get('X-Amz-Algorithm')).toBe('AWS4-HMAC-SHA256');
    expect(url.searchParams.get('X-Amz-Expires')).toBe('300');
    expect(url.searchParams.get('X-Amz-SignedHeaders')).toBe('host');
    expect(url.searchParams.get('X-Amz-Signature')).toMatch(/^[a-f0-9]{64}$/);
    expect(result.expiresAt).toBe('2026-02-23T10:05:00.000Z');
  });

  it('builds presigned url from s3 image ref', () => {
    const now = new Date('2026-02-23T10:00:00.000Z');
    const result = buildS3SignedReadUrlFromRef({
      imageRef: 's3://chat-images/2026/02/test.webp',
      config,
      now,
    });

    expect(result).toEqual(
      expect.objectContaining({
        url: expect.stringContaining('/museum-private/chat-images/2026/02/test.webp?'),
        expiresAt: '2026-02-23T10:15:00.000Z',
      }),
    );
    expect(
      buildS3SignedReadUrlFromRef({
        imageRef: 'local://abc.jpg',
        config,
      }),
    ).toBeNull();
  });

  it('supports public read base urls and session tokens in presigned read urls', () => {
    const now = new Date('2026-02-23T10:00:00.000Z');
    const result = buildS3PresignedReadUrl({
      key: 'chat-images/2026/02/private.png',
      config: {
        ...config,
        publicBaseUrl: 'https://cdn.example.com/{bucket}',
        sessionToken: 'session-token-abc',
      },
      ttlSeconds: 120,
      now,
    });

    const url = new URL(result.url);
    expect(url.origin).toBe('https://cdn.example.com');
    expect(url.pathname).toBe('/museum-private/chat-images/2026/02/private.png');
    expect(url.searchParams.get('X-Amz-Security-Token')).toBe('session-token-abc');
  });

  it('uploads image bytes with a signed PUT request', async () => {
    const received = await new Promise<{
      path: string;
      method: string;
      headers: http.IncomingHttpHeaders;
      body: Buffer;
      imageRef: string;
    }>((resolve, reject) => {
      let requestPayload:
        | {
            path: string;
            method: string;
            headers: http.IncomingHttpHeaders;
            body: Buffer;
          }
        | undefined;
      let savedImageRef: string | undefined;
      let settled = false;

      const maybeResolve = () => {
        if (settled || !requestPayload || !savedImageRef) {
          return;
        }
        settled = true;
        resolve({
          ...requestPayload,
          imageRef: savedImageRef,
        });
      };

      const server = http.createServer((req, res) => {
        const chunks: Buffer[] = [];
        req.on('data', (chunk) => chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk)));
        req.on('end', () => {
          res.statusCode = 200;
          res.end('');
          requestPayload = {
            path: req.url || '',
            method: req.method || '',
            headers: req.headers,
            body: Buffer.concat(chunks),
          };
          maybeResolve();
        });
      });

      server.on('error', reject);
      server.listen(0, '127.0.0.1', async () => {
        try {
          const address = server.address();
          if (!address || typeof address === 'string') {
            throw new Error('Failed to bind local test server');
          }

          const storage = new S3CompatibleImageStorage({
            ...config,
            endpoint: `http://127.0.0.1:${address.port}`,
            objectKeyPrefix: 'staging',
            sessionToken: 'upload-session-token',
            requestTimeoutMs: 5000,
          });

          savedImageRef = await storage.save({
            base64: Buffer.from('hello-image').toString('base64'),
            mimeType: 'image/png',
            objectKey: 'chat-images/2026/02/user-42/session-abc/custom.png',
          });
          maybeResolve();
          setImmediate(() => server.close());
        } catch (error) {
          server.close();
          reject(error);
        }
      });
    });

    expect(received.method).toBe('PUT');
    expect(received.path).toBe(
      '/museum-private/staging/chat-images/2026/02/user-42/session-abc/custom.png',
    );
    expect(received.headers['content-type']).toBe('image/png');
    expect(received.headers.authorization).toContain('AWS4-HMAC-SHA256');
    expect(received.headers['x-amz-date']).toEqual(expect.any(String));
    expect(received.headers['x-amz-content-sha256']).toMatch(/^[a-f0-9]{64}$/);
    expect(received.headers['x-amz-security-token']).toBe('upload-session-token');
    expect(received.body.toString('utf8')).toBe('hello-image');
    expect(received.imageRef).toBe(
      's3://staging/chat-images/2026/02/user-42/session-abc/custom.png',
    );
  });

  describe('listObjectsByPrefix', () => {
    it('parses ListObjectsV2 XML response and extracts keys', async () => {
      const listXml = `<?xml version="1.0" encoding="UTF-8"?>
        <ListBucketResult>
          <IsTruncated>false</IsTruncated>
          <Contents><Key>chat-images/2026/03/user-42/session-1/a.png</Key></Contents>
          <Contents><Key>chat-images/2026/03/user-42/session-2/b.jpg</Key></Contents>
          <Contents><Key>chat-images/2026/03/user-99/session-3/c.png</Key></Contents>
        </ListBucketResult>`;

      const result = await withTestServer(listXml, async (port) => {
        return listObjectsByPrefix(
          { ...config, endpoint: `http://127.0.0.1:${port}`, requestTimeoutMs: 5000 },
          'chat-images/',
        );
      });

      expect(result.keys).toEqual([
        'chat-images/2026/03/user-42/session-1/a.png',
        'chat-images/2026/03/user-42/session-2/b.jpg',
        'chat-images/2026/03/user-99/session-3/c.png',
      ]);
      expect(result.nextToken).toBeUndefined();
    });

    it('handles truncated responses with continuation token', async () => {
      const listXml = `<?xml version="1.0" encoding="UTF-8"?>
        <ListBucketResult>
          <IsTruncated>true</IsTruncated>
          <NextContinuationToken>token-abc-123</NextContinuationToken>
          <Contents><Key>chat-images/2026/03/user-1/s/a.png</Key></Contents>
        </ListBucketResult>`;

      const result = await withTestServer(listXml, async (port) => {
        return listObjectsByPrefix(
          { ...config, endpoint: `http://127.0.0.1:${port}`, requestTimeoutMs: 5000 },
          'chat-images/',
        );
      });

      expect(result.keys).toEqual(['chat-images/2026/03/user-1/s/a.png']);
      expect(result.nextToken).toBe('token-abc-123');
    });
  });

  describe('deleteObjectsBatch', () => {
    it('sends correct DeleteObjects XML with Content-MD5', async () => {
      const keys = ['chat-images/2026/03/user-42/s1/a.png', 'chat-images/2026/03/user-42/s2/b.jpg'];

      const received = await withTestServer(
        '',
        async (port) => {
          await deleteObjectsBatch(
            { ...config, endpoint: `http://127.0.0.1:${port}`, requestTimeoutMs: 5000 },
            keys,
          );
          return null;
        },
        true,
      );

      expect(received.method).toBe('POST');
      expect(received.path).toContain('?delete=');
      expect(received.body).toContain('<Delete>');
      expect(received.body).toContain('<Quiet>true</Quiet>');
      expect(received.body).toContain('<Key>chat-images/2026/03/user-42/s1/a.png</Key>');
      expect(received.body).toContain('<Key>chat-images/2026/03/user-42/s2/b.jpg</Key>');
      expect(received.headers['content-md5']).toBeTruthy();
      expect(received.headers['content-type']).toBe('application/xml');
    });

    it('is a no-op for empty key list', async () => {
      // Should not throw or make any request
      await deleteObjectsBatch(config, []);
    });
  });

  it('encodes special characters in object keys (RFC 3986)', () => {
    const now = new Date('2026-02-23T10:00:00.000Z');
    const result = buildS3PresignedReadUrl({
      key: "chat-images/file's name!(test).png",
      config,
      ttlSeconds: 300,
      now,
    });

    // The URL should contain the encoded special characters
    expect(result.url).toContain('file');
    expect(result.url).not.toContain("'");
    expect(result.url).not.toContain('!');
    expect(result.url).not.toContain('(');
    expect(result.url).not.toContain(')');
    expect(result.url).not.toContain('*');
  });

  it('handles isS3ImageRef with null and undefined', () => {
    expect(isS3ImageRef(null)).toBe(false);
    expect(isS3ImageRef(undefined)).toBe(false);
    expect(isS3ImageRef('')).toBe(false);
  });

  describe('deleteByPrefix integration', () => {
    it('lists and deletes only matching user keys', async () => {
      const requests: Array<{ method: string; path: string; body: string }> = [];
      const listXml = `<?xml version="1.0" encoding="UTF-8"?>
        <ListBucketResult>
          <IsTruncated>false</IsTruncated>
          <Contents><Key>chat-images/2026/03/user-42/s1/a.png</Key></Contents>
          <Contents><Key>chat-images/2026/03/user-42/s2/b.jpg</Key></Contents>
          <Contents><Key>chat-images/2026/03/user-99/s3/c.png</Key></Contents>
        </ListBucketResult>`;

      await new Promise<void>((resolve, reject) => {
        const server = http.createServer((req, res) => {
          const chunks: Buffer[] = [];
          req.on('data', (chunk) =>
            chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk)),
          );
          req.on('end', () => {
            requests.push({
              method: req.method || '',
              path: req.url || '',
              body: Buffer.concat(chunks).toString('utf8'),
            });
            res.statusCode = 200;
            // Return list XML for GET, empty for POST
            res.end(req.method === 'GET' ? listXml : '');
          });
        });

        server.listen(0, '127.0.0.1', async () => {
          try {
            const address = server.address();
            if (!address || typeof address === 'string') throw new Error('bind failed');

            const storage = new S3CompatibleImageStorage({
              ...config,
              endpoint: `http://127.0.0.1:${address.port}`,
              requestTimeoutMs: 5000,
            });

            await storage.deleteByPrefix('user-42');
            server.close();
            resolve();
          } catch (err) {
            server.close();
            reject(err);
          }
        });
      });

      // Expect a GET (list) and a POST (delete)
      expect(requests.length).toBe(2);
      expect(requests[0].method).toBe('GET');
      expect(requests[1].method).toBe('POST');
      // Delete body should contain user-42 keys but NOT user-99
      expect(requests[1].body).toContain('user-42/s1/a.png');
      expect(requests[1].body).toContain('user-42/s2/b.jpg');
      expect(requests[1].body).not.toContain('user-99');
    });
  });
});

interface CapturedRequest {
  method: string;
  path: string;
  headers: http.IncomingHttpHeaders;
  body: string;
}

/** Helper: spins up a local HTTP server that responds with the given body. */
async function withTestServer<T>(
  responseBody: string,
  fn: (port: number) => Promise<T>,
): Promise<T>;
async function withTestServer<T>(
  responseBody: string,
  fn: (port: number) => Promise<T>,
  captureRequest: true,
): Promise<CapturedRequest>;
async function withTestServer<T>(
  responseBody: string,
  fn: (port: number) => Promise<T>,
  captureRequest?: boolean,
): Promise<T | CapturedRequest> {
  return new Promise((resolve, reject) => {
    let captured: CapturedRequest | undefined;
    const server = http.createServer((req, res) => {
      const chunks: Buffer[] = [];
      req.on('data', (chunk) => chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk)));
      req.on('end', () => {
        captured = {
          method: req.method || '',
          path: req.url || '',
          headers: req.headers,
          body: Buffer.concat(chunks).toString('utf8'),
        };
        res.statusCode = 200;
        res.end(responseBody);
      });
    });

    server.listen(0, '127.0.0.1', async () => {
      try {
        const address = server.address();
        if (!address || typeof address === 'string') throw new Error('bind failed');
        const result = await fn(address.port);
        server.close();
        resolve(captureRequest && captured ? captured : (result as T));
      } catch (err) {
        server.close();
        reject(err);
      }
    });
  });
}

