import { UnsplashClient } from '@modules/chat/adapters/secondary/unsplash.client';

let fetchSpy: jest.SpyInstance;

beforeEach(() => {
  fetchSpy = jest.spyOn(globalThis, 'fetch');
});

afterEach(() => {
  fetchSpy.mockRestore();
});

/** Helper: builds a realistic Unsplash API photo result object. */
const makeUnsplashResult = (overrides: Record<string, unknown> = {}) => ({
  urls: { regular: 'https://img.unsplash.com/regular.jpg', small: 'https://img.unsplash.com/small.jpg' },
  description: 'A beautiful painting',
  alt_description: 'oil on canvas',
  width: 1920,
  height: 1080,
  user: { name: 'Jane Doe' },
  ...overrides,
});

describe('UnsplashClient', () => {
  const client = new UnsplashClient('test-access-key');

  describe('successful search', () => {
    it('returns mapped photos for valid results', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [makeUnsplashResult()],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toHaveLength(1);
      expect(photos[0]).toEqual({
        url: 'https://img.unsplash.com/regular.jpg',
        thumbnailUrl: 'https://img.unsplash.com/small.jpg',
        caption: 'A beautiful painting',
        width: 1920,
        height: 1080,
        photographerName: 'Jane Doe',
      });
    });

    it('sends correct Authorization header and query params', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({ results: [] }),
      });

      await client.searchPhotos('starry night', 3);

      expect(fetchSpy).toHaveBeenCalledTimes(1);
      const [url, options] = fetchSpy.mock.calls[0] as [string, RequestInit];
      expect(url).toContain('query=starry%20night');
      expect(url).toContain('per_page=3');
      expect(url).toContain('orientation=landscape');
      expect((options.headers as Record<string, string>).Authorization).toBe(
        'Client-ID test-access-key',
      );
    });

    it('returns empty array for empty results', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({ results: [] }),
      });

      const photos = await client.searchPhotos('abstract');

      expect(photos).toEqual([]);
    });
  });

  describe('non-ok HTTP responses', () => {
    it('returns empty array on 401 Unauthorized', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: false,
        status: 401,
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });

    it('returns empty array on 429 Rate Limited', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: false,
        status: 429,
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });
  });

  describe('timeout / abort handling', () => {
    it('returns empty array on AbortError (timeout)', async () => {
      fetchSpy.mockImplementationOnce(
        () =>
          new Promise((_resolve, reject) => {
            setTimeout(() => {
              const err = new Error('This operation was aborted');
              err.name = 'AbortError';
              reject(err);
            }, 5);
          }),
      );

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });
  });

  describe('network error handling', () => {
    it('returns empty array on network failure', async () => {
      fetchSpy.mockRejectedValueOnce(new Error('Failed to fetch'));

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });

    it('returns empty array on non-Error throw', async () => {
      fetchSpy.mockRejectedValueOnce('string error');

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });
  });

  describe('null safety — mapResult() via searchPhotos()', () => {
    it('filters out results with missing urls object', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [{ description: 'no urls', width: 100, height: 100 }],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });

    it('filters out results where urls.regular is missing', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [{ urls: { small: 'https://img.unsplash.com/small.jpg' }, width: 100, height: 100 }],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });

    it('filters out results where urls.small is missing', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [{ urls: { regular: 'https://img.unsplash.com/regular.jpg' }, width: 100, height: 100 }],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });

    it('uses alt_description when description is null', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [makeUnsplashResult({ description: null })],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toHaveLength(1);
      expect(photos[0].caption).toBe('oil on canvas');
    });

    it('uses empty string caption when both description and alt_description are missing', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [makeUnsplashResult({ description: null, alt_description: null })],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toHaveLength(1);
      expect(photos[0].caption).toBe('');
    });

    it('defaults width and height to 0 when not numbers', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [makeUnsplashResult({ width: 'wide', height: undefined })],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toHaveLength(1);
      expect(photos[0].width).toBe(0);
      expect(photos[0].height).toBe(0);
    });

    it('defaults photographerName to "Unknown" when user is missing', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [makeUnsplashResult({ user: undefined })],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toHaveLength(1);
      expect(photos[0].photographerName).toBe('Unknown');
    });

    it('defaults photographerName to "Unknown" when user.name is not a string', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [makeUnsplashResult({ user: { name: 42 } })],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toHaveLength(1);
      expect(photos[0].photographerName).toBe('Unknown');
    });

    it('filters out null entries in results array', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          results: [null, undefined, makeUnsplashResult()],
        }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toHaveLength(1);
    });

    it('returns empty array when data.results is not an array', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({ results: 'not-an-array' }),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });

    it('returns empty array when data.results is undefined', async () => {
      fetchSpy.mockResolvedValueOnce({
        ok: true,
        json: async () => ({}),
      });

      const photos = await client.searchPhotos('monet');

      expect(photos).toEqual([]);
    });
  });
});

tests/unit/auth/changeEmail.useCase.test.source:
import bcrypt from 'bcrypt';
import { ChangeEmailUseCase } from '@modules/auth/core/useCase/changeEmail.useCase';
import { ConfirmEmailChangeUseCase } from '@modules/auth/core/useCase/confirmEmailChange.useCase';
import type { IUserRepository } from '@modules/auth/core/domain/user.repository.interface';
import type { User } from '@modules/auth/core/domain/user.entity';
import type { EmailService } from '@shared/email/email.port';

jest.mock('bcrypt', () => ({
  ...jest.requireActual('bcrypt'),
  compare: jest.fn(),
}));

const HASHED_PASSWORD = '$2b$12$existinghash';

const makeUser = (overrides: Partial<User> = {}): User =>
  ({
    id: 1,
    email: 'user@test.com',
    password: HASHED_PASSWORD,
    firstname: 'Test',
    lastname: 'User',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  }) as User;

const makeUserRepo = (user: User | null = makeUser()) =>
  ({
    getUserById: jest.fn().mockResolvedValue(user),
    getUserByEmail: jest.fn().mockResolvedValue(null),
    setEmailChangeToken: jest.fn().mockResolvedValue(undefined),
    consumeEmailChangeToken: jest.fn().mockResolvedValue(user),
  }) as unknown as jest.Mocked<
    Pick<
      IUserRepository,
      'getUserById' | 'getUserByEmail' | 'setEmailChangeToken' | 'consumeEmailChangeToken'
    >
  >;

const makeEmailService = (): jest.Mocked<EmailService> => ({
  sendEmail: jest.fn().mockResolvedValue(undefined),
});

describe('ChangeEmailUseCase', () => {
  beforeEach(() => {
    (bcrypt.compare as jest.Mock).mockReset();
  });

  it('sends confirmation email and stores hashed token on success', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValueOnce(true);
    const repo = makeUserRepo();
    const emailService = makeEmailService();
    const useCase = new ChangeEmailUseCase(
      repo as unknown as IUserRepository,
      emailService,
      'https://app.musaium.com',
    );

    const token = await useCase.execute(1, 'new@test.com', 'ValidPass1');

    expect(token).toMatch(/^[0-9a-f]{64}$/); // 32 bytes hex
    expect(repo.getUserById).toHaveBeenCalledWith(1);
    expect(repo.getUserByEmail).toHaveBeenCalledWith('new@test.com');
    expect(repo.setEmailChangeToken).toHaveBeenCalledWith(
      1,
      expect.any(String), // hashed token
      'new@test.com',
      expect.any(Date),
    );
    expect(emailService.sendEmail).toHaveBeenCalledWith(
      'new@test.com',
      'Confirm your Musaium email change',
      expect.stringContaining(token),
    );
  });

  it('rejects wrong current password', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValueOnce(false);
    const repo = makeUserRepo();
    const useCase = new ChangeEmailUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute(1, 'new@test.com', 'wrongPass')).rejects.toMatchObject({
      message: 'Current password is incorrect',
      statusCode: 400,
    });
  });

  it('rejects social-only account (no password)', async () => {
    const repo = makeUserRepo(makeUser({ password: null }));
    const useCase = new ChangeEmailUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute(1, 'new@test.com', 'anything')).rejects.toMatchObject({
      message: 'Cannot change email for social-only accounts',
      statusCode: 400,
    });
  });

  it('throws 404 for non-existent user', async () => {
    const repo = makeUserRepo(null);
    const useCase = new ChangeEmailUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute(999, 'new@test.com', 'pass')).rejects.toMatchObject({
      message: 'User not found',
      statusCode: 404,
    });
  });

  it('rejects same email as current', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValueOnce(true);
    const repo = makeUserRepo(makeUser({ email: 'same@test.com' }));
    const useCase = new ChangeEmailUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute(1, 'same@test.com', 'ValidPass1')).rejects.toMatchObject({
      message: 'New email must be different from current email',
      statusCode: 400,
    });
  });

  it('rejects email already in use by another user', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValueOnce(true);
    const repo = makeUserRepo();
    (repo.getUserByEmail as jest.Mock).mockResolvedValueOnce(
      makeUser({ id: 2, email: 'taken@test.com' }),
    );
    const useCase = new ChangeEmailUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute(1, 'taken@test.com', 'ValidPass1')).rejects.toMatchObject({
      message: 'This email is already in use',
      statusCode: 400,
    });
  });

  it('rejects invalid email format', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValueOnce(true);
    const repo = makeUserRepo();
    const useCase = new ChangeEmailUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute(1, 'not-an-email', 'ValidPass1')).rejects.toMatchObject({
      message: 'Invalid email format',
      statusCode: 400,
    });
  });

  it('normalizes email to lowercase and trimmed', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValueOnce(true);
    const repo = makeUserRepo();
    const useCase = new ChangeEmailUseCase(repo as unknown as IUserRepository);

    await useCase.execute(1, '  NEW@Test.COM  ', 'ValidPass1');

    expect(repo.getUserByEmail).toHaveBeenCalledWith('new@test.com');
    expect(repo.setEmailChangeToken).toHaveBeenCalledWith(
      1,
      expect.any(String),
      'new@test.com',
      expect.any(Date),
    );
  });

  it('does not throw when emailService.sendEmail fails — warns instead', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValueOnce(true);
    const repo = makeUserRepo();
    const emailService = makeEmailService();
    emailService.sendEmail.mockRejectedValue(new Error('SMTP timeout'));
    const useCase = new ChangeEmailUseCase(
      repo as unknown as IUserRepository,
      emailService,
      'https://app.musaium.com',
    );

    const token = await useCase.execute(1, 'new@test.com', 'ValidPass1');

    expect(token).toMatch(/^[0-9a-f]{64}$/); // 32 bytes hex
    expect(repo.setEmailChangeToken).toHaveBeenCalled();
  });

  it('sets token expiration roughly 1 hour in the future', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValueOnce(true);
    const repo = makeUserRepo();
    const useCase = new ChangeEmailUseCase(repo as unknown as IUserRepository);

    const before = Date.now();
    await useCase.execute(1, 'new@test.com', 'ValidPass1');
    const after = Date.now();

    const expiresArg = (repo.setEmailChangeToken as jest.Mock).mock.calls[0][3] as Date;
    expect(expiresArg.getTime()).toBeGreaterThanOrEqual(before + 3600000 - 100);
    expect(expiresArg.getTime()).toBeLessThanOrEqual(after + 3600000 + 100);
  });
});

describe('ConfirmEmailChangeUseCase', () => {
  it('confirms email change with valid token', async () => {
    const updatedUser = makeUser({ email: 'new@test.com' });
    const repo = makeUserRepo(updatedUser);
    const useCase = new ConfirmEmailChangeUseCase(repo as unknown as IUserRepository);

    const result = await useCase.execute('abcd1234');

    expect(result).toEqual({ confirmed: true });
    expect(repo.consumeEmailChangeToken).toHaveBeenCalledWith(expect.any(String));
  });

  it('rejects invalid or expired token', async () => {
    const repo = makeUserRepo();
    (repo.consumeEmailChangeToken as jest.Mock).mockResolvedValueOnce(null);
    const useCase = new ConfirmEmailChangeUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute('invalid-token')).rejects.toMatchObject({
      message: 'Invalid or expired email change token',
      statusCode: 400,
    });
  });

  it('rejects empty token', async () => {
    const repo = makeUserRepo();
    const useCase = new ConfirmEmailChangeUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute('   ')).rejects.toMatchObject({
      message: 'Email change token is required',
      statusCode: 400,
    });
  });
});

tests/unit/middleware/daily-chat-limit.t.source:
import type { RequestHandler } from 'express';
import type { CacheService } from '@shared/cache/cache.port';
import {
  dailyChatLimit,
  clearDailyChatLimitBuckets,
  setDailyChatLimitCacheService,
  _resetDailyChatLimitCacheService,
} from '@src/helpers/middleware/daily-chat-limit.middleware';

const makeMockReq = (overrides: Record<string, unknown> = {}): Parameters<RequestHandler>[0] =>
  ({
    ip: '10.0.0.1',
    socket: { remoteAddress: '10.0.0.1' },
    params: {},
    body: {},
    ...overrides,
  }) as unknown as Parameters<RequestHandler>[0];

const makeMockRes = () => {
  const res = {
    status: jest.fn().mockReturnThis(),
    json: jest.fn().mockReturnThis(),
  };
  return res as unknown as Parameters<RequestHandler>[1];
};

describe('dailyChatLimit middleware', () => {
  beforeEach(() => {
    clearDailyChatLimitBuckets();
  });
  afterEach(() => {
    clearDailyChatLimitBuckets();
  });

  it('allows requests under the limit', () => {
    const req = makeMockReq({ user: { id: 1 } });
    const res = makeMockRes();
    const next = jest.fn();

    dailyChatLimit(req, res, next);

    expect(next).toHaveBeenCalledWith();
    expect((res as unknown as { status: jest.Mock }).status).not.toHaveBeenCalled();
  });

  it('blocks requests at the limit with 429', () => {
    const req = makeMockReq({ user: { id: 2 } });

    // Exhaust the limit (default 100)
    for (let i = 0; i < 100; i++) {
      const res = makeMockRes();
      const next = jest.fn();
      dailyChatLimit(req, res, next);
      expect(next).toHaveBeenCalledWith();
    }

    // The 101st request should be blocked
    const res = makeMockRes();
    const next = jest.fn();
    dailyChatLimit(req, res, next);

    expect(next).toHaveBeenCalledWith(
      expect.objectContaining({
        statusCode: 429,
        code: 'DAILY_LIMIT_REACHED',
        message: 'Daily chat limit reached',
      }),
    );
  });

  it('resets counter on a new day', () => {
    const req = makeMockReq({ user: { id: 3 } });

    // Use up the limit
    for (let i = 0; i < 100; i++) {
      const res = makeMockRes();
      const next = jest.fn();
      dailyChatLimit(req, res, next);
    }

    // Verify blocked
    const blockedRes = makeMockRes();
    const blockedNext = jest.fn();
    dailyChatLimit(req, blockedRes, blockedNext);
    expect(blockedNext).toHaveBeenCalledWith(expect.objectContaining({ statusCode: 429 }));

    // Simulate next day by advancing fake timers past midnight
    jest.useFakeTimers();
    jest.setSystemTime(new Date(Date.now() + 24 * 60 * 60 * 1000));

    // Should be allowed again on the new day
    const res = makeMockRes();
    const next = jest.fn();
    dailyChatLimit(req, res, next);
    expect(next).toHaveBeenCalledWith();

    jest.useRealTimers();
  });

  it('skips if no user (unauthenticated)', () => {
    const req = makeMockReq(); // no user property
    const res = makeMockRes();
    const next = jest.fn();

    dailyChatLimit(req, res, next);

    expect(next).toHaveBeenCalledWith();
    expect((res as unknown as { status: jest.Mock }).status).not.toHaveBeenCalled();
  });

  it('skips if user has no id', () => {
    const req = makeMockReq({ user: {} });
    const res = makeMockRes();
    const next = jest.fn();

    dailyChatLimit(req, res, next);

    expect(next).toHaveBeenCalledWith();
  });
});

// ---------------------------------------------------------------------------
// Redis distributed path
// ---------------------------------------------------------------------------

/** Creates a mock CacheService with jest.fn() stubs for every method. */
const makeMockCacheService = (
  overrides: Partial<Record<keyof CacheService, jest.Mock>> = {},
): CacheService & Record<keyof CacheService, jest.Mock> =>
  ({
    get: jest.fn().mockResolvedValue(null),
    set: jest.fn().mockResolvedValue(undefined),
    del: jest.fn().mockResolvedValue(undefined),
    delByPrefix: jest.fn().mockResolvedValue(undefined),
    setNx: jest.fn().mockResolvedValue(true),
    ping: jest.fn().mockResolvedValue(true),
    ...overrides,
  }) as unknown as CacheService & Record<keyof CacheService, jest.Mock>;

describe('dailyChatLimit middleware — Redis distributed path', () => {
  beforeEach(() => {
    clearDailyChatLimitBuckets();
    _resetDailyChatLimitCacheService();
  });
  afterEach(() => {
    clearDailyChatLimitBuckets();
    _resetDailyChatLimitCacheService();
  });

  const todayStr = (): string => new Date().toISOString().slice(0, 10);

  it('stores and retrieves counts via cache when CacheService is registered', async () => {
    const cache = makeMockCacheService();
    setDailyChatLimitCacheService(cache);

    const req = makeMockReq({ user: { id: 100 } });
    const res = makeMockRes();
    const next = jest.fn();

    dailyChatLimit(req, res, next);

    // Wait for the async chain to settle
    await new Promise(process.nextTick);

    const expectedKey = `daily-chat:100:${todayStr()}`;
    expect(cache.get).toHaveBeenCalledWith(expectedKey);
    expect(cache.set).toHaveBeenCalledWith(expectedKey, 1, expect.any(Number));

    // Verify TTL is a positive number (seconds until midnight)
    const ttlArg = (cache.set as jest.Mock).mock.calls[0][2] as number;
    expect(ttlArg).toBeGreaterThan(0);
    expect(ttlArg).toBeLessThanOrEqual(86400);

    expect(next).toHaveBeenCalledWith();
  });

  it('returns 429 when cache returns count at limit', async () => {
    const cache = makeMockCacheService({
      get: jest.fn().mockResolvedValue(100), // default limit is 100
    });
    setDailyChatLimitCacheService(cache);

    const req = makeMockReq({ user: { id: 200 } });
    const res = makeMockRes();
    const next = jest.fn();

    dailyChatLimit(req, res, next);

    await new Promise(process.nextTick);

    expect(next).toHaveBeenCalledWith(
      expect.objectContaining({
        statusCode: 429,
        code: 'DAILY_LIMIT_REACHED',
        message: 'Daily chat limit reached',
      }),
    );
    // Should not attempt to set when at limit
    expect(cache.set).not.toHaveBeenCalled();
  });

  it('allows request and increments count when cache returns count under limit', async () => {
    const cache = makeMockCacheService({
      get: jest.fn().mockResolvedValue(42),
    });
    setDailyChatLimitCacheService(cache);

    const req = makeMockReq({ user: { id: 300 } });
    const res = makeMockRes();
    const next = jest.fn();

    dailyChatLimit(req, res, next);

    await new Promise(process.nextTick);

    expect(next).toHaveBeenCalledWith();
    expect(cache.set).toHaveBeenCalledWith(`daily-chat:300:${todayStr()}`, 43, expect.any(Number));
  });

  it('falls back to in-memory when cache.get rejects', async () => {
    const cache = makeMockCacheService({
      get: jest.fn().mockRejectedValue(new Error('Redis connection lost')),
    });
    setDailyChatLimitCacheService(cache);

    const req = makeMockReq({ user: { id: 400 } });
    const res = makeMockRes();
    const next = jest.fn();

    dailyChatLimit(req, res, next);

    await new Promise(process.nextTick);

    // Request should still pass via in-memory fallback
    expect(next).toHaveBeenCalledWith();
    // cache.set should NOT be called because get already failed
    expect(cache.set).not.toHaveBeenCalled();
  });

  it('still completes request when cache.set rejects', async () => {
    const cache = makeMockCacheService({
      get: jest.fn().mockResolvedValue(5),
      set: jest.fn().mockRejectedValue(new Error('Redis write timeout')),
    });
    setDailyChatLimitCacheService(cache);

    const req = makeMockReq({ user: { id: 500 } });
    const res = makeMockRes();
    const next = jest.fn();

    dailyChatLimit(req, res, next);

    await new Promise(process.nextTick);

    // cache.set was called but rejected — falls back to in-memory
    expect(cache.set).toHaveBeenCalled();
    // Request still passes via the in-memory fallback in .catch()
    expect(next).toHaveBeenCalledWith();
  });
});

