import { TokenCleanupService } from '@modules/auth/core/useCase/tokenCleanup.service';
import type { IRefreshTokenRepository } from '@modules/auth/core/domain/refresh-token.repository.interface';

jest.mock('@shared/logger/logger', () => ({
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

const { logger } = jest.requireMock('@shared/logger/logger') as {
  logger: { info: jest.Mock; warn: jest.Mock; error: jest.Mock };
};

const makeRefreshTokenRepo = (deleteResult = 5) => ({
  deleteExpiredTokens: jest.fn().mockResolvedValue(deleteResult),
});

const makeCacheService = (setNxResult = true) => ({
  get: jest.fn(),
  set: jest.fn(),
  del: jest.fn(),
  delByPrefix: jest.fn(),
  setNx: jest.fn().mockResolvedValue(setNxResult),
  ping: jest.fn().mockResolvedValue(true),
});

describe('TokenCleanupService', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  // ── runCleanup ──────────────────────────────────────────────────

  it('runs cleanup when lock is acquired (setNx returns true)', async () => {
    const repo = makeRefreshTokenRepo(42);
    const cache = makeCacheService(true);
    const service = new TokenCleanupService(repo as unknown as IRefreshTokenRepository, cache);

    const deleted = await service.runCleanup();

    expect(cache.setNx).toHaveBeenCalledWith('token-cleanup:lock', true, 300);
    expect(repo.deleteExpiredTokens).toHaveBeenCalledWith(10000);
    expect(deleted).toBe(42);
  });

  it('skips cleanup when lock is held (setNx returns false)', async () => {
    const repo = makeRefreshTokenRepo();
    const cache = makeCacheService(false);
    const service = new TokenCleanupService(repo as unknown as IRefreshTokenRepository, cache);

    const deleted = await service.runCleanup();

    expect(cache.setNx).toHaveBeenCalled();
    expect(repo.deleteExpiredTokens).not.toHaveBeenCalled();
    expect(deleted).toBe(0);
    expect(logger.info).toHaveBeenCalledWith('token_cleanup_skipped', { reason: 'lock_held' });
  });

  it('runs cleanup without cache (no lock)', async () => {
    const repo = makeRefreshTokenRepo(10);
    const service = new TokenCleanupService(repo as unknown as IRefreshTokenRepository, undefined);

    const deleted = await service.runCleanup();

    expect(repo.deleteExpiredTokens).toHaveBeenCalledWith(10000);
    expect(deleted).toBe(10);
  });

  it('returns 0 and logs error if deleteExpiredTokens throws', async () => {
    const repo = makeRefreshTokenRepo();
    repo.deleteExpiredTokens.mockRejectedValue(new Error('DB down'));
    const service = new TokenCleanupService(repo as unknown as IRefreshTokenRepository, undefined);

    const deleted = await service.runCleanup();

    expect(deleted).toBe(0);
    expect(logger.error).toHaveBeenCalledWith('token_cleanup_failed', { error: 'DB down' });
  });

  it('logs completed with count when tokens were deleted', async () => {
    const repo = makeRefreshTokenRepo(15);
    const service = new TokenCleanupService(repo as unknown as IRefreshTokenRepository, undefined);

    await service.runCleanup();

    expect(logger.info).toHaveBeenCalledWith('token_cleanup_completed', { deleted: 15 });
  });

  it('does not log completed when no tokens were deleted', async () => {
    const repo = makeRefreshTokenRepo(0);
    const service = new TokenCleanupService(repo as unknown as IRefreshTokenRepository, undefined);

    await service.runCleanup();

    expect(logger.info).not.toHaveBeenCalledWith('token_cleanup_completed', expect.anything());
  });

  // ── Scheduler ───────────────────────────────────────────────────

  describe('startScheduler / stopScheduler', () => {
    beforeEach(() => {
      jest.useFakeTimers();
    });

    afterEach(() => {
      jest.useRealTimers();
    });

    it('startScheduler fires runCleanup at the specified interval', async () => {
      const repo = makeRefreshTokenRepo(3);
      const service = new TokenCleanupService(
        repo as unknown as IRefreshTokenRepository,
        undefined,
      );

      service.startScheduler(1000);
      expect(logger.info).toHaveBeenCalledWith('token_cleanup_scheduler_started', {
        intervalMs: 1000,
      });

      // Advance past one interval
      jest.advanceTimersByTime(1000);
      // Allow the async runCleanup to settle
      await Promise.resolve();

      expect(repo.deleteExpiredTokens).toHaveBeenCalledTimes(1);

      service.stopScheduler();
    });

    it('stopScheduler halts the interval', async () => {
      const repo = makeRefreshTokenRepo(1);
      const service = new TokenCleanupService(
        repo as unknown as IRefreshTokenRepository,
        undefined,
      );

      service.startScheduler(500);
      service.stopScheduler();

      jest.advanceTimersByTime(2000);
      await Promise.resolve();

      expect(repo.deleteExpiredTokens).not.toHaveBeenCalled();
    });

    it('startScheduler called twice is a no-op on second call', () => {
      const repo = makeRefreshTokenRepo();
      const service = new TokenCleanupService(
        repo as unknown as IRefreshTokenRepository,
        undefined,
      );

      service.startScheduler(1000);
      service.startScheduler(1000);

      // Logger should only be called once for scheduler_started
      const schedulerStartCalls = logger.info.mock.calls.filter(
        (call: unknown[]) => call[0] === 'token_cleanup_scheduler_started',
      );
      expect(schedulerStartCalls).toHaveLength(1);

      service.stopScheduler();
    });

    it('stopScheduler is safe to call when no scheduler is running', () => {
      const repo = makeRefreshTokenRepo();
      const service = new TokenCleanupService(
        repo as unknown as IRefreshTokenRepository,
        undefined,
      );

      // Should not throw
      expect(() => service.stopScheduler()).not.toThrow();
    });
  });
});

tests/unit/shared/sentry-wrapper.test.ts.source:
/**
 * Sentry wrapper tests — verifies both disabled (no DSN) and enabled (with DSN) paths.
 *
 * The existing sentry.test.ts covers the disabled/no-op branches.
 * This file complements it by also verifying the enabled path via @sentry/node mocks.
 */

const mockSentryInit = jest.fn();
const mockSetupExpressErrorHandler = jest.fn();
const mockCaptureException = jest.fn();
const mockSetUser = jest.fn();
const mockWithScope = jest.fn((cb: (scope: { setTag: jest.Mock }) => void) => {
  cb({ setTag: jest.fn() });
});
const mockStartSpan = jest.fn((_ctx: Record<string, unknown>, cb: (span: unknown) => unknown) =>
  cb({ setAttribute: jest.fn() }),
);
const mockGetDefaultIntegrations = jest.fn(() => []);

jest.mock('@sentry/node', () => ({
  init: mockSentryInit,
  setupExpressErrorHandler: mockSetupExpressErrorHandler,
  captureException: mockCaptureException,
  setUser: mockSetUser,
  withScope: mockWithScope,
  startSpan: mockStartSpan,
  getDefaultIntegrations: mockGetDefaultIntegrations,
}));

jest.mock('@shared/logger/logger', () => ({
  logger: { info: jest.fn(), warn: jest.fn(), error: jest.fn() },
}));

describe('sentry wrapper', () => {
  const originalEnv = { ...process.env };

  afterEach(() => {
    process.env = { ...originalEnv };
    jest.restoreAllMocks();
    jest.resetModules();
  });

  // ── Disabled path (no DSN) ────────────────────────────────────

  describe('when SENTRY_DSN is not configured', () => {
    it('initSentry does not call Sentry.init', () => {
      jest.isolateModules(() => {
        delete process.env.SENTRY_DSN;
        const { initSentry } = require('@shared/observability/sentry');
        initSentry();
        expect(mockSentryInit).not.toHaveBeenCalled();
      });
    });

    it('captureExceptionWithContext is a no-op', () => {
      jest.isolateModules(() => {
        delete process.env.SENTRY_DSN;
        const { captureExceptionWithContext } = require('@shared/observability/sentry');
        captureExceptionWithContext(new Error('test'), { requestId: 'r1' });
        expect(mockWithScope).not.toHaveBeenCalled();
        expect(mockCaptureException).not.toHaveBeenCalled();
      });
    });

    it('setUser is a no-op', () => {
      jest.isolateModules(() => {
        delete process.env.SENTRY_DSN;
        const { setUser } = require('@shared/observability/sentry');
        setUser({ id: '42' });
        expect(mockSetUser).not.toHaveBeenCalled();
      });
    });

    it('setupSentryExpressErrorHandler is a no-op', () => {
      jest.isolateModules(() => {
        delete process.env.SENTRY_DSN;
        const { setupSentryExpressErrorHandler } = require('@shared/observability/sentry');
        setupSentryExpressErrorHandler({} as import('express').Express);
        expect(mockSetupExpressErrorHandler).not.toHaveBeenCalled();
      });
    });

    it('startSpan calls callback with NOOP_SPAN', () => {
      jest.isolateModules(() => {
        delete process.env.SENTRY_DSN;
        const { startSpan } = require('@shared/observability/sentry');
        const result = startSpan({ name: 'op', op: 'test' }, () => 'value');
        expect(result).toBe('value');
        // Sentry.startSpan should NOT be called — the wrapper uses the proxy
        expect(mockStartSpan).not.toHaveBeenCalled();
      });
    });
  });

  // ── Enabled path (with DSN) ───────────────────────────────────

  describe('when SENTRY_DSN is configured', () => {
    it('initSentry calls Sentry.init with correct config', () => {
      jest.isolateModules(() => {
        process.env.SENTRY_DSN = 'https://key@sentry.io/123';
        const { initSentry, isSentryEnabled } = require('@shared/observability/sentry');
        initSentry();
        expect(mockSentryInit).toHaveBeenCalledWith(
          expect.objectContaining({
            dsn: 'https://key@sentry.io/123',
          }),
        );
        expect(isSentryEnabled()).toBe(true);
      });
    });

    it('captureExceptionWithContext delegates to Sentry.withScope', () => {
      jest.isolateModules(() => {
        process.env.SENTRY_DSN = 'https://key@sentry.io/123';
        const { initSentry, captureExceptionWithContext } = require('@shared/observability/sentry');
        initSentry();
        const err = new Error('boom');
        captureExceptionWithContext(err, { requestId: 'r1', path: '/api/test' });
        expect(mockWithScope).toHaveBeenCalled();
        expect(mockCaptureException).toHaveBeenCalledWith(err);
      });
    });

    it('setUser delegates to Sentry.setUser', () => {
      jest.isolateModules(() => {
        process.env.SENTRY_DSN = 'https://key@sentry.io/123';
        const { initSentry, setUser } = require('@shared/observability/sentry');
        initSentry();
        setUser({ id: '42' });
        expect(mockSetUser).toHaveBeenCalledWith({ id: '42' });
      });
    });

    it('setupSentryExpressErrorHandler delegates to Sentry', () => {
      jest.isolateModules(() => {
        process.env.SENTRY_DSN = 'https://key@sentry.io/123';
        const {
          initSentry,
          setupSentryExpressErrorHandler,
        } = require('@shared/observability/sentry');
        initSentry();
        const fakeApp = {} as import('express').Express;
        setupSentryExpressErrorHandler(fakeApp);
        expect(mockSetupExpressErrorHandler).toHaveBeenCalledWith(fakeApp);
      });
    });

    it('startSpan delegates to Sentry.startSpan when initialized', () => {
      jest.isolateModules(() => {
        process.env.SENTRY_DSN = 'https://key@sentry.io/123';
        const { initSentry, startSpan } = require('@shared/observability/sentry');
        initSentry();
        const ctx = { name: 'db.query', op: 'db' };
        const callback = jest.fn(() => 'result');
        startSpan(ctx, callback);
        expect(mockStartSpan).toHaveBeenCalledWith(ctx, callback);
      });
    });
  });
});

