import {
  EmailSupportContactNotifier,
  NoopSupportContactNotifier,
} from '@modules/support/adapters/secondary/support-contact-email.notifier';
import type { EmailService } from '@shared/email/email.port';
import type { SupportContactPayload } from '@modules/support/domain/support-contact-notifier.port';

jest.mock('@shared/logger/logger', () => ({
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

const { logger } = jest.requireMock('@shared/logger/logger') as {
  logger: { info: jest.Mock; warn: jest.Mock; error: jest.Mock };
};

const makePayload = (overrides: Partial<SupportContactPayload> = {}): SupportContactPayload => ({
  name: 'Ada Lovelace',
  email: 'ada@example.com',
  message: 'I have a question about the exhibit.',
  ...overrides,
});

describe('EmailSupportContactNotifier', () => {
  let sendEmail: jest.Mock;
  let emailService: EmailService;
  let notifier: EmailSupportContactNotifier;

  beforeEach(() => {
    sendEmail = jest.fn().mockResolvedValue(undefined);
    emailService = { sendEmail };
    notifier = new EmailSupportContactNotifier(emailService, 'support@museum.test');
  });

  it('sends email with correct recipient and subject', async () => {
    await notifier.notify(makePayload());

    expect(sendEmail).toHaveBeenCalledTimes(1);
    expect(sendEmail).toHaveBeenCalledWith(
      'support@museum.test',
      '[Musaium Support] Ada Lovelace <ada@example.com>',
      expect.any(String),
    );
  });

  it('escapes HTML special characters in name, email, and message', async () => {
    const payload = makePayload({
      name: '<script>alert("xss")</script>',
      email: 'user&co@"test\'.com',
      message: 'Test & verify <b>bold</b> "quotes" \'single\'',
    });

    await notifier.notify(payload);

    const html = sendEmail.mock.calls[0][2] as string;
    expect(html).toContain('&lt;script&gt;alert(&quot;xss&quot;)&lt;/script&gt;');
    expect(html).toContain('user&amp;co@&quot;test&#39;.com');
    expect(html).toContain('Test &amp; verify &lt;b&gt;bold&lt;/b&gt; &quot;quotes&quot; &#39;single&#39;');
    // Verify no raw HTML special characters leaked through
    expect(html).not.toContain('<script>');
    expect(html).not.toContain('<b>bold</b>');
  });

  it('replaces newlines with <br/> in message', async () => {
    const payload = makePayload({
      message: 'Line one\nLine two\nLine three',
    });

    await notifier.notify(payload);

    const html = sendEmail.mock.calls[0][2] as string;
    expect(html).toContain('Line one<br/>Line two<br/>Line three');
  });

  it('truncates subject to 200 characters', async () => {
    const longName = 'A'.repeat(250);
    const payload = makePayload({ name: longName });

    await notifier.notify(payload);

    const subject = sendEmail.mock.calls[0][1] as string;
    expect(subject.length).toBeLessThanOrEqual(200);
  });

  it('includes all HTML sections in output', async () => {
    await notifier.notify(makePayload());

    const html = sendEmail.mock.calls[0][2] as string;
    expect(html).toContain('<h2>New Musaium Support Contact</h2>');
    expect(html).toContain('<strong>Name:</strong>');
    expect(html).toContain('<strong>Email:</strong>');
    expect(html).toContain('<strong>Request ID:</strong>');
    expect(html).toContain('<strong>IP:</strong>');
    expect(html).toContain('<strong>User-Agent:</strong>');
    expect(html).toContain('<hr/>');
  });

  it('uses "unknown" for missing ip and userAgent, "n/a" for requestId', async () => {
    const payload = makePayload({
      ip: undefined,
      requestId: undefined,
      userAgent: undefined,
    });

    await notifier.notify(payload);

    const html = sendEmail.mock.calls[0][2] as string;
    expect(html).toContain('unknown'); // ip and userAgent default
    expect(html).toContain('n/a'); // requestId default
  });

  it('uses provided optional fields when present', async () => {
    const payload = makePayload({
      ip: '192.168.1.1',
      requestId: 'req-abc-123',
      userAgent: 'TestAgent/1.0',
    });

    await notifier.notify(payload);

    const html = sendEmail.mock.calls[0][2] as string;
    expect(html).toContain('192.168.1.1');
    expect(html).toContain('req-abc-123');
    expect(html).toContain('TestAgent/1.0');
  });

  it('escapes ampersand in all five positions', async () => {
    const payload = makePayload({
      name: 'R&D',
      email: 'r&d@test.com',
      message: 'Testing & verifying',
    });

    await notifier.notify(payload);

    const html = sendEmail.mock.calls[0][2] as string;
    expect(html).toContain('R&amp;D');
    expect(html).toContain('r&amp;d@test.com');
    expect(html).toContain('Testing &amp; verifying');
  });
});

describe('NoopSupportContactNotifier', () => {
  const notifier = new NoopSupportContactNotifier();

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('resolves without throwing', async () => {
    await expect(notifier.notify(makePayload())).resolves.toBeUndefined();
  });

  it('logs a warning with requestId and hasIp info', async () => {
    await notifier.notify(makePayload({ requestId: 'req-42', ip: '10.0.0.1' }));

    expect(logger.warn).toHaveBeenCalledWith('support_contact_notifier_noop', {
      requestId: 'req-42',
      hasIp: true,
    });
  });

  it('logs hasIp as false when ip is undefined', async () => {
    await notifier.notify(makePayload({ ip: undefined }));

    expect(logger.warn).toHaveBeenCalledWith(
      'support_contact_notifier_noop',
      expect.objectContaining({ hasIp: false }),
    );
  });
});

tests/unit/chat/semaphore.test.ts.source:
import {
  Semaphore,
  SemaphoreQueueFullError,
  SemaphoreTimeoutError,
} from '@modules/chat/application/semaphore';

describe('Semaphore', () => {
  beforeEach(() => {
    jest.useFakeTimers();
  });

  afterEach(() => {
    jest.useRealTimers();
  });

  it('allows immediate acquisition when slots are available', async () => {
    const sem = new Semaphore(2);
    const results: number[] = [];

    const p = sem.use(async () => {
      results.push(1);
      return 42;
    });

    const value = await p;
    expect(value).toBe(42);
    expect(results).toEqual([1]);
  });

  it('queues tasks when max concurrent is reached', async () => {
    const sem = new Semaphore(1);
    const order: string[] = [];

    let resolveFirst!: () => void;
    const firstBlocker = new Promise<void>((resolve) => {
      resolveFirst = resolve;
    });

    const p1 = sem.use(async () => {
      order.push('first-start');
      await firstBlocker;
      order.push('first-end');
    });

    const p2 = sem.use(async () => {
      order.push('second');
    });

    // Let microtasks run
    await Promise.resolve();
    expect(order).toEqual(['first-start']);
    expect(sem.queueSize).toBe(1);

    resolveFirst();
    await p1;
    await p2;

    expect(order).toEqual(['first-start', 'first-end', 'second']);
  });

  it('respects the concurrent limit', async () => {
    jest.useRealTimers();
    const sem = new Semaphore({ maxConcurrent: 2, maxQueueSize: 200, acquireTimeoutMs: 5_000 });
    let concurrent = 0;
    let maxConcurrent = 0;

    const resolvers: (() => void)[] = [];
    const promises: Promise<void>[] = [];

    for (let i = 0; i < 5; i++) {
      promises.push(
        sem.use(async () => {
          concurrent++;
          maxConcurrent = Math.max(maxConcurrent, concurrent);
          await new Promise<void>((resolve) => {
            resolvers.push(resolve);
          });
          concurrent--;
        }),
      );
      // Let the task start if a slot is available
      await new Promise((r) => setImmediate(r));
    }

    expect(sem.inFlightCount).toBe(2);

    // Release tasks one by one, letting each queued task start
    while (resolvers.length > 0) {
      const resolve = resolvers.shift()!;
      resolve();
      await new Promise((r) => setImmediate(r));
    }

    await Promise.all(promises);
    expect(maxConcurrent).toBe(2);
    jest.useFakeTimers();
  });

  it('releases semaphore slot even when task throws', async () => {
    const sem = new Semaphore(1);

    await expect(
      sem.use(async () => {
        throw new Error('task failed');
      }),
    ).rejects.toThrow('task failed');

    // Should be able to acquire again
    const result = await sem.use(async () => 'ok');
    expect(result).toBe('ok');
  });

  it('rejects when queue is full', async () => {
    const sem = new Semaphore({
      maxConcurrent: 1,
      maxQueueSize: 1,
      acquireTimeoutMs: 30_000,
    });

    // Fill the slot
    let resolveFirst!: () => void;
    const blocker = new Promise<void>((resolve) => {
      resolveFirst = resolve;
    });

    const p1 = sem.use(async () => {
      await blocker;
    });

    // Fill the queue (1 item)
    const p2 = sem.use(async () => 'queued');

    await Promise.resolve();
    expect(sem.queueSize).toBe(1);

    // This should be rejected
    await expect(sem.use(async () => 'overflow')).rejects.toThrow(SemaphoreQueueFullError);

    resolveFirst();
    await p1;
    await p2;
  });

  it('times out when waiting too long to acquire', async () => {
    const sem = new Semaphore({
      maxConcurrent: 1,
      maxQueueSize: 100,
      acquireTimeoutMs: 100,
    });

    let resolveFirst!: () => void;
    const blocker = new Promise<void>((resolve) => {
      resolveFirst = resolve;
    });

    const p1 = sem.use(async () => {
      await blocker;
    });

    const p2 = sem.use(async () => 'should-timeout');

    // Advance past timeout
    jest.advanceTimersByTime(101);

    await expect(p2).rejects.toThrow(SemaphoreTimeoutError);

    resolveFirst();
    await p1;
  });

  it('correctly reports queueSize and inFlightCount', async () => {
    const sem = new Semaphore(1);

    expect(sem.queueSize).toBe(0);
    expect(sem.inFlightCount).toBe(0);

    let resolveFirst!: () => void;
    const blocker = new Promise<void>((resolve) => {
      resolveFirst = resolve;
    });

    const p1 = sem.use(async () => {
      await blocker;
    });

    await Promise.resolve();
    expect(sem.inFlightCount).toBe(1);
    expect(sem.queueSize).toBe(0);

    const p2 = sem.use(async () => 'queued');
    await Promise.resolve();
    expect(sem.queueSize).toBe(1);

    resolveFirst();
    await p1;
    await p2;

    expect(sem.inFlightCount).toBe(0);
    expect(sem.queueSize).toBe(0);
  });

  it('accepts a numeric shorthand for maxConcurrent', () => {
    const sem = new Semaphore(5);
    expect(sem.inFlightCount).toBe(0);
    expect(sem.queueSize).toBe(0);
  });

  it('releases slot to next queued task in FIFO order', async () => {
    const sem = new Semaphore(1);
    const order: number[] = [];

    let resolveFirst!: () => void;
    const blocker = new Promise<void>((resolve) => {
      resolveFirst = resolve;
    });

    const p1 = sem.use(async () => {
      await blocker;
      order.push(1);
    });

    const p2 = sem.use(async () => {
      order.push(2);
    });

    const p3 = sem.use(async () => {
      order.push(3);
    });

    resolveFirst();
    await p1;
    await p2;
    await p3;

    expect(order).toEqual([1, 2, 3]);
  });
});

tests/unit/middleware/upload-admission.t.source:
import { createUploadAdmissionMiddleware } from '@src/helpers/middleware/upload-admission.middleware';

import type { Request, Response, NextFunction } from 'express';

interface MockResponse extends Response {
  triggerClose: () => void;
}

const mockReq = (contentType = ''): Request =>
  ({
    headers: { 'content-type': contentType },
  }) as unknown as Request;

const mockRes = (): MockResponse => {
  const closeHandlers: (() => void)[] = [];
  return {
    status: jest.fn().mockReturnThis(),
    json: jest.fn().mockReturnThis(),
    on: jest.fn((event: string, handler: () => void) => {
      if (event === 'close') {
        closeHandlers.push(handler);
      }
    }),
    triggerClose() {
      for (const h of closeHandlers) h();
    },
  } as unknown as MockResponse;
};

describe('uploadAdmissionMiddleware', () => {
  it('passes through non-multipart requests without counting', () => {
    const middleware = createUploadAdmissionMiddleware(2);
    const req = mockReq('application/json');
    const res = mockRes();
    const next = jest.fn() as NextFunction;

    middleware(req, res, next);

    expect(next).toHaveBeenCalledTimes(1);
    expect(res.status).not.toHaveBeenCalled();
  });

  it('allows multipart requests under the limit', () => {
    const middleware = createUploadAdmissionMiddleware(2);
    const req = mockReq('multipart/form-data; boundary=something');
    const res = mockRes();
    const next = jest.fn() as NextFunction;

    middleware(req, res, next);

    expect(next).toHaveBeenCalledTimes(1);
    expect(res.status).not.toHaveBeenCalled();
  });

  it('returns 503 when concurrent limit is reached', () => {
    const middleware = createUploadAdmissionMiddleware(1);

    // First request — fills the slot
    const req1 = mockReq('multipart/form-data');
    const res1 = mockRes();
    const next1 = jest.fn() as NextFunction;
    middleware(req1, res1, next1);
    expect(next1).toHaveBeenCalledTimes(1);

    // Second request — should be rejected
    const req2 = mockReq('multipart/form-data');
    const res2 = mockRes();
    const next2 = jest.fn() as NextFunction;
    middleware(req2, res2, next2);

    expect(next2).not.toHaveBeenCalled();
    expect(res2.status).toHaveBeenCalledWith(503);
    expect(res2.json).toHaveBeenCalledWith(
      expect.objectContaining({
        error: expect.objectContaining({
          code: 'SERVICE_UNAVAILABLE',
        }),
      }),
    );
  });

  it('releases slot after response close and allows new requests', () => {
    const middleware = createUploadAdmissionMiddleware(1);

    // First request
    const req1 = mockReq('multipart/form-data');
    const res1 = mockRes();
    const next1 = jest.fn() as NextFunction;
    middleware(req1, res1, next1);
    expect(next1).toHaveBeenCalledTimes(1);

    // Simulate response close
    res1.triggerClose();

    // Second request should now succeed
    const req2 = mockReq('multipart/form-data');
    const res2 = mockRes();
    const next2 = jest.fn() as NextFunction;
    middleware(req2, res2, next2);
    expect(next2).toHaveBeenCalledTimes(1);
  });

  it('releases slot on aborted connection (close event)', () => {
    const middleware = createUploadAdmissionMiddleware(1);

    // Fill the slot
    const req1 = mockReq('multipart/form-data');
    const res1 = mockRes();
    const next1 = jest.fn() as NextFunction;
    middleware(req1, res1, next1);

    // Simulate abort via close event
    res1.triggerClose();

    // New request should succeed
    const req2 = mockReq('multipart/form-data');
    const res2 = mockRes();
    const next2 = jest.fn() as NextFunction;
    middleware(req2, res2, next2);
    expect(next2).toHaveBeenCalledTimes(1);
  });

  it('uses default maxConcurrent of 50 when not specified', () => {
    const middleware = createUploadAdmissionMiddleware();

    // Should allow 50 concurrent requests
    const responses: ReturnType<typeof mockRes>[] = [];
    for (let i = 0; i < 50; i++) {
      const req = mockReq('multipart/form-data');
      const res = mockRes();
      const next = jest.fn() as NextFunction;
      middleware(req, res, next);
      expect(next).toHaveBeenCalledTimes(1);
      responses.push(res);
    }

    // 51st should be rejected
    const req51 = mockReq('multipart/form-data');
    const res51 = mockRes();
    const next51 = jest.fn() as NextFunction;
    middleware(req51, res51, next51);
    expect(next51).not.toHaveBeenCalled();
    expect(res51.status).toHaveBeenCalledWith(503);

    // Clean up
    for (const res of responses) {
      res.triggerClose();
    }
  });

  it('never decrements below zero', () => {
    const middleware = createUploadAdmissionMiddleware(1);

    const req1 = mockReq('multipart/form-data');
    const res1 = mockRes();
    const next1 = jest.fn() as NextFunction;
    middleware(req1, res1, next1);

    // Double close should not break anything
    res1.triggerClose();
    res1.triggerClose();

    // Should still work correctly
    const req2 = mockReq('multipart/form-data');
    const res2 = mockRes();
    const next2 = jest.fn() as NextFunction;
    middleware(req2, res2, next2);
    expect(next2).toHaveBeenCalledTimes(1);

    // And the second slot should not be magically opened
    const req3 = mockReq('multipart/form-data');
    const res3 = mockRes();
    const next3 = jest.fn() as NextFunction;
    middleware(req3, res3, next3);
    expect(next3).not.toHaveBeenCalled();
    expect(res3.status).toHaveBeenCalledWith(503);
  });
});

