import {
  DeleteAccountUseCase,
  ImageCleanupPort,
} from '@modules/auth/core/useCase/deleteAccount.useCase';
import type { IUserRepository } from '@modules/auth/core/domain/user.repository.interface';
import type { User } from '@modules/auth/core/domain/user.entity';

const makeUser = (overrides: Partial<User> = {}): User =>
  ({
    id: 1,
    email: 'user@test.com',
    password: '$2b$12$hash',
    firstname: 'Test',
    lastname: 'User',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  }) as User;

const makeUserRepo = (user: User | null = makeUser()) => ({
  getUserById: jest.fn().mockResolvedValue(user),
  deleteUser: jest.fn().mockResolvedValue(undefined),
});

const makeImageStorage = (): jest.Mocked<ImageCleanupPort> => ({
  deleteByPrefix: jest.fn().mockResolvedValue(undefined),
});

describe('DeleteAccountUseCase', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  // ── Happy paths ──────────────────────────────────────────────────

  it('deletes user and cleans up images when imageStorage is provided', async () => {
    const repo = makeUserRepo();
    const imageStorage = makeImageStorage();
    const useCase = new DeleteAccountUseCase(repo as unknown as IUserRepository, imageStorage);

    await useCase.execute(1);

    expect(repo.getUserById).toHaveBeenCalledWith(1);
    expect(imageStorage.deleteByPrefix).toHaveBeenCalledWith('user-1');
    expect(repo.deleteUser).toHaveBeenCalledWith(1);
  });

  it('deletes user without image cleanup when imageStorage is not provided', async () => {
    const repo = makeUserRepo();
    const useCase = new DeleteAccountUseCase(repo as unknown as IUserRepository);

    await useCase.execute(1);

    expect(repo.getUserById).toHaveBeenCalledWith(1);
    expect(repo.deleteUser).toHaveBeenCalledWith(1);
  });

  // ── Error paths ──────────────────────────────────────────────────

  it('throws 404 when user does not exist', async () => {
    const repo = makeUserRepo(null);
    const useCase = new DeleteAccountUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute(999)).rejects.toMatchObject({
      message: 'User not found',
      statusCode: 404,
    });

    expect(repo.deleteUser).not.toHaveBeenCalled();
  });

  // ── Edge cases (RGPD resilience) ─────────────────────────────────

  it('continues deletion when imageStorage.deleteByPrefix fails (RGPD resilience)', async () => {
    const repo = makeUserRepo();
    const imageStorage = makeImageStorage();
    imageStorage.deleteByPrefix.mockRejectedValue(new Error('S3 connection timeout'));
    const useCase = new DeleteAccountUseCase(repo as unknown as IUserRepository, imageStorage);

    // Should NOT throw
    await useCase.execute(1);

    expect(imageStorage.deleteByPrefix).toHaveBeenCalledWith('user-1');
    // User must still be deleted even if images fail
    expect(repo.deleteUser).toHaveBeenCalledWith(1);
  });

  it('calls deleteByPrefix before deleteUser (images before user)', async () => {
    const repo = makeUserRepo();
    const imageStorage = makeImageStorage();
    const callOrder: string[] = [];

    imageStorage.deleteByPrefix.mockImplementation(async () => {
      callOrder.push('deleteByPrefix');
    });
    repo.deleteUser.mockImplementation(async () => {
      callOrder.push('deleteUser');
    });

    const useCase = new DeleteAccountUseCase(repo as unknown as IUserRepository, imageStorage);

    await useCase.execute(1);

    expect(callOrder).toEqual(['deleteByPrefix', 'deleteUser']);
  });

  it('uses correct prefix format "user-{userId}"', async () => {
    const repo = makeUserRepo(makeUser({ id: 42 }));
    const imageStorage = makeImageStorage();
    const useCase = new DeleteAccountUseCase(repo as unknown as IUserRepository, imageStorage);

    await useCase.execute(42);

    expect(imageStorage.deleteByPrefix).toHaveBeenCalledWith('user-42');
  });

  it('does not call deleteUser when getUserById throws', async () => {
    const repo = makeUserRepo();
    repo.getUserById.mockRejectedValue(new Error('DB connection lost'));
    const useCase = new DeleteAccountUseCase(repo as unknown as IUserRepository);

    await expect(useCase.execute(1)).rejects.toThrow('DB connection lost');
    expect(repo.deleteUser).not.toHaveBeenCalled();
  });
});

tests/unit/auth/jwt-pii-strip.test.ts.source:
import jwt from 'jsonwebtoken';
import bcrypt from 'bcrypt';
import { AuthSessionService } from '@modules/auth/core/useCase/authSession.service';
import { GetProfileUseCase } from '@modules/auth/core/useCase/getProfile.useCase';
import type { IUserRepository } from '@modules/auth/core/domain/user.repository.interface';
import type { User } from '@modules/auth/core/domain/user.entity';

jest.mock('bcrypt', () => ({
  ...jest.requireActual('bcrypt'),
  compare: jest.fn(),
}));

// env.ts resolves accessTokenSecret from JWT_ACCESS_SECRET → JWT_SECRET → 'local-dev-jwt-secret'
// We need to read it after the module is loaded to sign test tokens with the same secret.
import { env } from '@src/config/env';

const getAccessSecret = () => env.auth.accessTokenSecret;

const makeUser = (overrides: Partial<User> = {}): User =>
  ({
    id: 42,
    email: 'alice@example.com',
    password: '$2b$12$hashed',
    firstname: 'Alice',
    lastname: 'Doe',
    role: 'visitor',
    onboarding_completed: false,
    createdAt: new Date('2025-01-01'),
    updatedAt: new Date('2025-06-01'),
    ...overrides,
  }) as User;

const makeUserRepo = (user: User | null): IUserRepository =>
  ({
    getUserByEmail: jest.fn().mockResolvedValue(user),
    getUserById: jest.fn().mockResolvedValue(user),
  }) as unknown as IUserRepository;

const makeRefreshTokenRepo = () =>
  ({
    insert: jest.fn().mockResolvedValue(undefined),
    findByJti: jest.fn().mockResolvedValue(null),
    revokeByJti: jest.fn().mockResolvedValue(undefined),
    revokeFamily: jest.fn().mockResolvedValue(undefined),
    rotate: jest.fn().mockResolvedValue(undefined),
    deleteExpiredTokens: jest.fn().mockResolvedValue(0),
  }) as unknown as ConstructorParameters<typeof AuthSessionService>[1];

describe('S2-22: JWT PII strip', () => {
  it('verifyAccessToken returns { id, role } only — no email, firstname, lastname', () => {
    const service = new AuthSessionService(makeUserRepo(makeUser()), makeRefreshTokenRepo());

    const token = jwt.sign(
      { sub: '42', type: 'access', jti: 'test-jti', role: 'visitor' },
      getAccessSecret(),
      { expiresIn: '15m' },
    );

    const result = service.verifyAccessToken(token);
    expect(result).toEqual({ id: 42, role: 'visitor', museumId: null });
    expect(result).not.toHaveProperty('email');
    expect(result).not.toHaveProperty('firstname');
    expect(result).not.toHaveProperty('lastname');
  });

  it('issued access token contains role but no PII fields when decoded', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValue(true);
    const user = makeUser();
    const service = new AuthSessionService(makeUserRepo(user), makeRefreshTokenRepo());

    const session = await service.login('alice@example.com', 'ValidPass1');

    const decoded = jwt.decode(session.accessToken) as Record<string, unknown>;
    expect(decoded.sub).toBe('42');
    expect(decoded.type).toBe('access');
    expect(typeof decoded.jti).toBe('string');
    expect((decoded.jti as string).length).toBeGreaterThan(0);
    expect(decoded.role).toBe('visitor');
    expect(decoded).not.toHaveProperty('email');
    expect(decoded).not.toHaveProperty('firstname');
    expect(decoded).not.toHaveProperty('lastname');
  });

  it('login response body still includes user with PII (SafeUser)', async () => {
    (bcrypt.compare as jest.Mock).mockResolvedValue(true);
    const user = makeUser();
    const service = new AuthSessionService(makeUserRepo(user), makeRefreshTokenRepo());

    const session = await service.login('alice@example.com', 'ValidPass1');
    expect(session.user).toEqual({
      id: 42,
      email: 'alice@example.com',
      firstname: 'Alice',
      lastname: 'Doe',
      role: 'visitor',
      museumId: null,
      onboardingCompleted: false,
    });
  });
});

describe('GetProfileUseCase', () => {
  it('returns full profile for existing user', async () => {
    const user = makeUser();
    const useCase = new GetProfileUseCase(makeUserRepo(user));

    const result = await useCase.execute(42);
    expect(result).toEqual({
      id: 42,
      email: 'alice@example.com',
      firstname: 'Alice',
      lastname: 'Doe',
      role: 'visitor',
      onboardingCompleted: false,
      createdAt: new Date('2025-01-01'),
      updatedAt: new Date('2025-06-01'),
    });
  });

  it('returns null for deleted/non-existent user', async () => {
    const useCase = new GetProfileUseCase(makeUserRepo(null));
    const result = await useCase.execute(999);
    expect(result).toBeNull();
  });
});

