      useCase.execute({
        name: 'Ada',
        email: 'ada@example.com',
        message: 'too short',
      }),
    ).rejects.toMatchObject({
      statusCode: 400,
      message: 'message must be between 10 and 5000 characters',
    });
    expect(notify).not.toHaveBeenCalled();
  });
});

