import { buildLocalizedFallback, FALLBACK_TEMPLATES } from '@shared/i18n/fallback-messages';
import type { SupportedLocale } from '@shared/i18n/locale';

describe('buildLocalizedFallback', () => {
  it('builds English fallback without location in museum mode', () => {
    const result = buildLocalizedFallback('en', {
      recap: 'The painting shows a starry night.',
      museumMode: true,
    });

    expect(result).toContain('Quick summary: The painting shows a starry night.');
    expect(result).toContain('Next step: compare composition details');
    expect(result).toContain('Would you like');
  });

  it('builds English fallback with location prefix', () => {
    const result = buildLocalizedFallback('en', {
      location: 'Room 12',
      recap: 'A marble sculpture.',
      museumMode: true,
    });

    expect(result).toContain('You are currently near Room 12.');
    expect(result).toContain('A marble sculpture.');
  });

  it('uses standardHint when museumMode is false', () => {
    const result = buildLocalizedFallback('en', {
      recap: 'Some recap.',
      museumMode: false,
    });

    expect(result).toContain('Helpful angle');
    expect(result).not.toContain('Next step');
  });

  it('works for all supported locales', () => {
    const locales: SupportedLocale[] = ['en', 'fr', 'es', 'de', 'it', 'ja', 'zh'];

    for (const locale of locales) {
      const result = buildLocalizedFallback(locale, {
        recap: 'test recap',
        museumMode: true,
      });

      expect(result.length).toBeGreaterThan(0);
      expect(result).toContain('test recap');
    }
  });

  it('builds French fallback with location', () => {
    const result = buildLocalizedFallback('fr', {
      location: 'Salle 5',
      recap: 'Un portrait.',
      museumMode: false,
    });

    expect(result).toContain('Vous êtes près de Salle 5.');
    expect(result).toContain('Piste utile');
  });

  it('all locales have locationPrefix as a function', () => {
    const locales: SupportedLocale[] = ['en', 'fr', 'es', 'de', 'it', 'ja', 'zh'];

    for (const locale of locales) {
      const templates = FALLBACK_TEMPLATES[locale];
      expect(typeof templates.locationPrefix).toBe('function');
      const prefix = templates.locationPrefix('Test Room');
      expect(prefix.length).toBeGreaterThan(0);
      expect(prefix).toContain('Test Room');
    }
  });
});

tests/unit/auth/login-rate-limiter.test..source:
import {
  checkLoginRateLimit,
  recordFailedLogin,
  clearLoginAttempts,
  _resetAllAttempts,
} from '@modules/auth/core/useCase/login-rate-limiter';

beforeEach(() => {
  _resetAllAttempts();
});

describe('login-rate-limiter', () => {
  it('allows first attempt', () => {
    expect(() => checkLoginRateLimit('user@test.com')).not.toThrow();
  });

  it('allows up to 9 failed attempts', () => {
    for (let i = 0; i < 9; i++) {
      recordFailedLogin('user@test.com');
    }
    expect(() => checkLoginRateLimit('user@test.com')).not.toThrow();
  });

  it('blocks after 10 failed attempts', () => {
    for (let i = 0; i < 10; i++) {
      recordFailedLogin('user@test.com');
    }
    expect(() => checkLoginRateLimit('user@test.com')).toThrow('Too many login attempts');
  });

  it('clears attempts on successful login', () => {
    for (let i = 0; i < 9; i++) {
      recordFailedLogin('user@test.com');
    }
    clearLoginAttempts('user@test.com');
    expect(() => checkLoginRateLimit('user@test.com')).not.toThrow();
  });

  it('is case-insensitive', () => {
    for (let i = 0; i < 10; i++) {
      recordFailedLogin('User@Test.COM');
    }
    expect(() => checkLoginRateLimit('user@test.com')).toThrow();
  });

  it('resets expired entries on check', () => {
    jest.useFakeTimers();

    // Record 10 failed attempts (would block)
    for (let i = 0; i < 10; i++) {
      recordFailedLogin('expired@test.com');
    }
    expect(() => checkLoginRateLimit('expired@test.com')).toThrow();

    // Advance past the 10-minute window
    jest.advanceTimersByTime(10 * 60 * 1000 + 1);

    // Entry should now be expired and removed on check
    expect(() => checkLoginRateLimit('expired@test.com')).not.toThrow();

    jest.useRealTimers();
  });

  it('resets expired entries on record', () => {
    jest.useFakeTimers();

    recordFailedLogin('expired-record@test.com');

    // Advance past the window
    jest.advanceTimersByTime(10 * 60 * 1000 + 1);

    // Recording again should start fresh (count=1, not count=2)
    recordFailedLogin('expired-record@test.com');

    // Should not throw (only 1 attempt after reset)
    expect(() => checkLoginRateLimit('expired-record@test.com')).not.toThrow();

    jest.useRealTimers();
  });
});

