import { ListMuseumsUseCase } from '@modules/museum/core/useCase/listMuseums.useCase';
import { InMemoryMuseumRepository } from 'tests/helpers/museum/inMemoryMuseumRepository';

describe('ListMuseumsUseCase', () => {
  let useCase: ListMuseumsUseCase;
  let repo: InMemoryMuseumRepository;

  beforeEach(() => {
    repo = new InMemoryMuseumRepository();
    useCase = new ListMuseumsUseCase(repo);
  });

  it('returns all museums', async () => {
    await repo.create({ name: 'Louvre', slug: 'louvre' });
    await repo.create({ name: 'Orsay', slug: 'orsay' });

    const result = await useCase.execute();

    expect(result).toHaveLength(2);
    expect(result.map((m) => m.name)).toEqual(['Louvre', 'Orsay']);
  });

  it('returns only active museums when activeOnly is true', async () => {
    await repo.create({ name: 'Active Museum', slug: 'active' });
    const inactive = await repo.create({ name: 'Inactive Museum', slug: 'inactive' });
    await repo.update(inactive.id, { isActive: false });

    const result = await useCase.execute({ activeOnly: true });

    expect(result).toHaveLength(1);
    expect(result[0].name).toBe('Active Museum');
  });

  it('returns all museums including inactive when activeOnly is false', async () => {
    await repo.create({ name: 'Active', slug: 'active' });
    const inactive = await repo.create({ name: 'Inactive', slug: 'inactive' });
    await repo.update(inactive.id, { isActive: false });

    const result = await useCase.execute({ activeOnly: false });

    expect(result).toHaveLength(2);
  });

  it('returns empty array when no museums exist', async () => {
    const result = await useCase.execute();

    expect(result).toEqual([]);
  });

  it('returns all museums when no opts provided', async () => {
    await repo.create({ name: 'Solo', slug: 'solo' });

    const result = await useCase.execute();

    expect(result).toHaveLength(1);
  });
});

tests/unit/shared/i18n/guardrail-refusal.source:
import { GUARDRAIL_REFUSALS } from '@shared/i18n/guardrail-refusals';
import { SUPPORTED_LOCALES } from '@shared/i18n/locale';

describe('guardrail refusals', () => {
  it('has entries for all 7 supported locales', () => {
    for (const locale of SUPPORTED_LOCALES) {
      expect(typeof GUARDRAIL_REFUSALS[locale]).toBe('object');
      expect(GUARDRAIL_REFUSALS[locale]).not.toBeNull();
    }
  });

  it.each(SUPPORTED_LOCALES)('locale "%s" has non-empty insult and default', (locale) => {
    const messages = GUARDRAIL_REFUSALS[locale];
    expect(typeof messages.insult).toBe('string');
    expect(messages.insult.length).toBeGreaterThan(10);
    expect(typeof messages.default).toBe('string');
    expect(messages.default.length).toBeGreaterThan(10);
  });

  it('produces 14 total refusal strings (7 locales x 2 variants)', () => {
    const variants: (keyof (typeof GUARDRAIL_REFUSALS)['en'])[] = ['insult', 'default'];
    let count = 0;
    for (const locale of SUPPORTED_LOCALES) {
      for (const variant of variants) {
        expect(typeof GUARDRAIL_REFUSALS[locale][variant]).toBe('string');
        count++;
      }
    }
    expect(count).toBe(14);
  });

  it('en refusals mention art/museum/heritage', () => {
    const en = GUARDRAIL_REFUSALS.en;
    expect(en.insult.toLowerCase()).toContain('art');
    expect(en.default.toLowerCase()).toContain('art');
  });

  it('fr refusals are in French', () => {
    const fr = GUARDRAIL_REFUSALS.fr;
    expect(fr.insult).toContain('insultes');
    expect(fr.default).toContain('réponds uniquement');
  });

  it('all locales have distinct default messages', () => {
    const defaults = SUPPORTED_LOCALES.map((l) => GUARDRAIL_REFUSALS[l].default);
    const unique = new Set(defaults);
    expect(unique.size).toBe(SUPPORTED_LOCALES.length);
  });
});

tests/contract/health/health.contract.te.source:
import { buildHealthPayload } from '@shared/routers/api.router';

describe('health response contract', () => {
  const previousAppVersion = process.env.APP_VERSION;
  const previousCommitSha = process.env.COMMIT_SHA;
  const previousGithubSha = process.env.GITHUB_SHA;

  afterEach(() => {
    if (previousAppVersion === undefined) {
      delete process.env.APP_VERSION;
    } else {
      process.env.APP_VERSION = previousAppVersion;
    }

    if (previousCommitSha === undefined) {
      delete process.env.COMMIT_SHA;
    } else {
      process.env.COMMIT_SHA = previousCommitSha;
    }

    if (previousGithubSha === undefined) {
      delete process.env.GITHUB_SHA;
    } else {
      process.env.GITHUB_SHA = previousGithubSha;
    }
  });

  it('includes environment/version fields without breaking existing checks object', () => {
    process.env.APP_VERSION = '1.2.3-test';
    delete process.env.COMMIT_SHA;
    delete process.env.GITHUB_SHA;

    const payload = buildHealthPayload({
      checks: { database: 'up' },
      llmConfigured: true,
    });

    expect(payload.status).toBe('ok');
    expect(payload.checks.database).toBe('up');
    expect(payload.checks.llmConfigured).toBe(true);
    expect(payload.environment).toBe('test');
    expect(payload.version).toBe('1.2.3-test');
    expect(typeof payload.timestamp).toBe('string');
    expect(payload).not.toHaveProperty('commitSha');
  });

  it('keeps commitSha optional and present when available', () => {
    process.env.APP_VERSION = '2.0.0';
    process.env.COMMIT_SHA = 'abc1234';

    const payload = buildHealthPayload({
      checks: { database: 'down' },
      llmConfigured: false,
    });

    expect(payload.status).toBe('degraded');
    expect(payload.commitSha).toBe('abc1234');
  });
});

