import { parseContext } from '@modules/chat/adapters/primary/http/chat-route.helpers';

describe('parseContext — payload size limit', () => {
  it('accepts a context object under the size limit', () => {
    const ctx = { location: 'Paris', museumMode: true, guideLevel: 'beginner', locale: 'fr' };
    const result = parseContext(ctx);
    expect(result).not.toBeNull();
    expect(result).not.toBeUndefined();
    expect(result?.location).toBe('Paris');
  });

  it('rejects a string context exceeding MAX_CONTEXT_BYTES', () => {
    const oversized = JSON.stringify({ location: 'x'.repeat(2100) });
    expect(() => parseContext(oversized)).toThrow('context payload too large');
  });

  it('rejects an object context exceeding MAX_CONTEXT_BYTES', () => {
    const oversized = { location: 'x'.repeat(2100) };
    expect(() => parseContext(oversized)).toThrow('context payload too large');
  });

  it('accepts a string context under the size limit', () => {
    const ctx = JSON.stringify({ location: 'Berlin', locale: 'de' });
    const result = parseContext(ctx);
    expect(result).not.toBeNull();
    expect(result).not.toBeUndefined();
    expect(result?.location).toBe('Berlin');
  });

  it('returns undefined for null/undefined/empty input', () => {
    expect(parseContext(undefined)).toBeUndefined();
    expect(parseContext(null)).toBeUndefined();
    expect(parseContext('')).toBeUndefined();
  });
});

tests/unit/auth/password-validation.test.source:
import { validatePassword } from '@shared/validation/password';

describe('validatePassword', () => {
  it('rejects empty password', () => {
    expect(validatePassword('')).toEqual({ valid: false, reason: 'Password is required' });
  });

  it('rejects too short', () => {
    expect(validatePassword('Ab1')).toEqual({
      valid: false,
      reason: expect.stringContaining('at least 8'),
    });
  });

  it('rejects too long', () => {
    const long = 'Aa1' + 'x'.repeat(126);
    expect(validatePassword(long)).toEqual({
      valid: false,
      reason: expect.stringContaining('at most 128'),
    });
  });

  it('rejects no lowercase', () => {
    expect(validatePassword('ABCDEFG1')).toEqual({
      valid: false,
      reason: expect.stringContaining('lowercase'),
    });
  });

  it('rejects no uppercase', () => {
    expect(validatePassword('abcdefg1')).toEqual({
      valid: false,
      reason: expect.stringContaining('uppercase'),
    });
  });

  it('rejects no digit', () => {
    expect(validatePassword('Abcdefgh')).toEqual({
      valid: false,
      reason: expect.stringContaining('digit'),
    });
  });

  it('accepts valid password', () => {
    expect(validatePassword('Abcdefg1')).toEqual({ valid: true });
  });

  it('accepts complex password', () => {
    expect(validatePassword('MyP@ssw0rd!#')).toEqual({ valid: true });
  });
});

tests/unit/shared/fire-and-forget.test.t.source:
import { fireAndForget } from '@shared/utils/fire-and-forget';
import { logger } from '@shared/logger/logger';

jest.mock('@shared/logger/logger', () => ({
  logger: { warn: jest.fn(), info: jest.fn(), error: jest.fn() },
}));

describe('fireAndForget', () => {
  beforeEach(() => jest.clearAllMocks());

  it('does not throw when promise resolves', () => {
    expect(() => {
      fireAndForget(Promise.resolve('ok'), 'test-ctx');
    }).not.toThrow();
  });

  it('logs a warning when promise rejects with an Error', async () => {
    const err = new Error('something broke');
    fireAndForget(Promise.reject(err), 'my-context');

    // Wait for microtask queue to flush
    await new Promise(process.nextTick);

    expect(logger.warn).toHaveBeenCalledWith('fire_and_forget_failed', {
      context: 'my-context',
      error: 'something broke',
    });
  });

  it('logs a warning when promise rejects with a non-Error value', async () => {
    fireAndForget(Promise.reject('string-error'), 'ctx');

    await new Promise(process.nextTick);

    expect(logger.warn).toHaveBeenCalledWith('fire_and_forget_failed', {
      context: 'ctx',
      error: 'string-error',
    });
  });
});

